-- ============================================================================
-- Quiz Seed: 2 Chronicles — Part 2 (Chapters 13–24)
-- 3 kids + 5 teens + 8 adults = 16 questions × 12 chapters = 192 total questions
-- ============================================================================

-- ═══ 2 Chronicles Chapter 13 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 13, 'kids', 1, 'Who was the king of Judah who fought against Jeroboam?', 'Abijah', 'Asa', 'Jehoshaphat', 'Rehoboam', 'a', '2 Chronicles 13:1 — "Now in the eighteenth year of king Jeroboam began Abijah to reign over Judah."'),
('2 Chronicles', 13, 'kids', 2, 'What kind of covenant did Abijah say God had made with David and his sons?', 'A covenant of salt', 'A covenant of fire', 'A covenant of water', 'A covenant of peace', 'a', '2 Chronicles 13:5 — "Ought ye not to know that the LORD God of Israel gave the kingdom over Israel to David for ever, even to him and to his sons by a covenant of salt?"'),
('2 Chronicles', 13, 'kids', 3, 'Who did Abijah say was fighting for Judah against Jeroboam?', 'God', 'The angels', 'The Egyptians', 'The Philistines', 'a', '2 Chronicles 13:12 — "And, behold, God himself is with us for our captain, and his priests with sounding trumpets to cry alarm against you."'),
-- Teens
('2 Chronicles', 13, 'teens', 1, 'How many soldiers did Abijah have compared to Jeroboam in their battle?', 'Abijah had 400,000 and Jeroboam had 800,000 chosen men', 'Abijah had 500,000 and Jeroboam had 500,000 men', 'Abijah had 300,000 and Jeroboam had 600,000 men', 'Abijah had 200,000 and Jeroboam had 800,000 men', 'a', '2 Chronicles 13:3 — "And Abijah set the battle in array with an army of valiant men of war, even four hundred thousand chosen men: Jeroboam also set the battle in array against him with eight hundred thousand chosen men."'),
('2 Chronicles', 13, 'teens', 2, 'On what mountain did Abijah stand and give his speech to Jeroboam?', 'Mount Zemaraim', 'Mount Carmel', 'Mount Moriah', 'Mount Ephraim', 'a', '2 Chronicles 13:4 — "And Abijah stood up upon mount Zemaraim, which is in mount Ephraim, and said, Hear me, thou Jeroboam, and all Israel."'),
('2 Chronicles', 13, 'teens', 3, 'What was Jeroboam''s military tactic against Abijah in the battle?', 'He set an ambushment behind Judah while the front army faced them', 'He attacked at night while Judah was sleeping', 'He cut off Judah''s water supply first', 'He sent spies to cause confusion in Judah''s camp', 'a', '2 Chronicles 13:13 — "But Jeroboam caused an ambushment to come about behind them: so they were before Judah, and the ambushment was behind them."'),
('2 Chronicles', 13, 'teens', 4, 'What did Judah do when they found themselves surrounded by Jeroboam''s army?', 'They cried unto the LORD and the priests sounded the trumpets', 'They retreated to the mountains', 'They sent messengers to make peace', 'They charged the enemy without fear', 'a', '2 Chronicles 13:14 — "And when Judah looked back, behold, the battle was before and behind: and they cried unto the LORD, and the priests sounded with the trumpets."'),
('2 Chronicles', 13, 'teens', 5, 'How many casualties did Israel suffer when God delivered them into Abijah''s hand?', 'Five hundred thousand chosen men fell slain', 'Two hundred thousand men were killed', 'Eight hundred thousand men perished', 'One hundred thousand men were slain', 'a', '2 Chronicles 13:17 — "And Abijah and his people slew them with a great slaughter: so there fell down slain of Israel five hundred thousand chosen men."'),
-- Adults
('2 Chronicles', 13, 'adults', 1, 'What accusation did Abijah make against Jeroboam regarding the priesthood and worship of Israel?', 'Jeroboam had driven out the sons of Aaron and the Levites and made priests of the lowest of the people for golden calves', 'Jeroboam had stolen the temple treasures from Jerusalem', 'Jeroboam had made a treaty with Egypt against Israel''s God', 'Jeroboam had burned the law of Moses in public', 'a', '2 Chronicles 13:9 — "Have ye not cast out the priests of the LORD, the sons of Aaron, and the Levites, and have made you priests after the manner of the nations of other lands?"'),
('2 Chronicles', 13, 'adults', 2, 'What did Abijah say distinguished Judah from Israel in terms of their religious practice?', 'Judah had not forsaken the LORD — they had priests of Aaron ministering and Levites in their work, offering morning and evening burnt offerings and incense', 'Judah had built a new temple surpassing Solomon''s', 'Judah''s army was stronger because of their obedience', 'Judah paid tithes to all the Levites faithfully', 'a', '2 Chronicles 13:10-11 — "But as for us, the LORD is our God, and we have not forsaken him; and the priests, which minister unto the LORD, are the sons of Aaron, and the Levites wait upon their business."'),
('2 Chronicles', 13, 'adults', 3, 'What cities did Abijah capture from Jeroboam during and after the battle?', 'Bethel, Jeshanah, and Ephrain with their surrounding villages', 'Samaria, Dan, and Beersheba', 'Shechem, Tirzah, and Penuel', 'Ramah, Gibeah, and Mizpah', 'a', '2 Chronicles 13:19 — "And Abijah pursued after Jeroboam, and took cities from him, Bethel with the towns thereof, and Jeshanah with the towns thereof, and Ephrain with the towns thereof."'),
('2 Chronicles', 13, 'adults', 4, 'What was the theological explanation the Chronicler gave for Judah''s victory over the numerically superior force?', 'The children of Israel were brought under at that time and the children of Judah prevailed because they relied upon the LORD God of their fathers', 'Judah had a superior military strategy devised by Abijah', 'God sent an angel to fight for Judah directly', 'Jeroboam''s soldiers refused to fight fellow Israelites', 'a', '2 Chronicles 13:18 — "Thus the children of Israel were brought under at that time, and the children of Judah prevailed, because they relied upon the LORD God of their fathers."'),
('2 Chronicles', 13, 'adults', 5, 'What happened to Jeroboam personally as a result of his opposition to Abijah and Judah?', 'The LORD struck him and he died', 'He was captured and held prisoner in Jerusalem', 'He fled to Egypt and never returned', 'He lost his throne to his son immediately', 'a', '2 Chronicles 13:20 — "Neither did Jeroboam recover strength again in the days of Abijah: and the LORD struck him, and he died."'),
('2 Chronicles', 13, 'adults', 6, 'How many wives and children did Abijah have, showing the extent of his dynasty?', 'Fourteen wives, twenty-two sons, and sixteen daughters', 'Ten wives, twelve sons, and eight daughters', 'Seven wives, thirty sons, and twenty daughters', 'Eighteen wives, forty sons, and thirty daughters', 'a', '2 Chronicles 13:21 — "But Abijah waxed mighty, and married fourteen wives, and begat twenty and two sons, and sixteen daughters."'),
('2 Chronicles', 13, 'adults', 7, 'Where are further details of Abijah''s acts, words, and ways recorded according to the Chronicler?', 'In the story of the prophet Iddo', 'In the book of the kings of Israel', 'In the annals of the palace scribes', 'In the records of the high priest', 'a', '2 Chronicles 13:22 — "And the rest of the acts of Abijah, and his ways, and his sayings, are written in the story of the prophet Iddo."'),
('2 Chronicles', 13, 'adults', 8, 'What does Abijah''s speech from Mount Zemaraim reveal about the Chronicler''s theological perspective on the division of the kingdom?', 'The Chronicler presents the north as in apostasy while the Davidic covenant and Levitical worship in Judah remain the legitimate expression of Israel''s religion', 'The Chronicler sees both kingdoms as equally sinful before God', 'The Chronicler blames Solomon rather than Jeroboam for the division', 'The Chronicler views the division as permanent and irreversible in God''s plan', 'a', '2 Chronicles 13:5 — "Ought ye not to know that the LORD God of Israel gave the kingdom over Israel to David for ever, even to him and to his sons by a covenant of salt?" showing covenant legitimacy resting with Judah.');

-- ═══ 2 Chronicles Chapter 14 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 14, 'kids', 1, 'Who was the king of Judah who had peace and rest during his early reign?', 'Asa', 'Abijah', 'Jehoshaphat', 'Joash', 'a', '2 Chronicles 14:1 — "So Abijah slept with his fathers...and Asa his son reigned in his stead. In his days the land was quiet ten years."'),
('2 Chronicles', 14, 'kids', 2, 'What did Asa ask God to give his people when a huge army came against him?', 'Help and rest against the mighty', 'Gold to pay for soldiers', 'A sign in the sky', 'A dream to tell him what to do', 'a', '2 Chronicles 14:11 — "And Asa cried unto the LORD his God, and said, LORD, it is nothing with thee to help, whether with many, or with them that have no power: help us, O LORD our God."'),
('2 Chronicles', 14, 'kids', 3, 'Who led the huge army of a million men that came against Asa?', 'Zerah the Ethiopian', 'Shishak the Egyptian', 'Benhadad of Syria', 'Pul the Assyrian', 'a', '2 Chronicles 14:9 — "And there came out against them Zerah the Ethiopian with an host of a thousand thousand, and three hundred chariots."'),
-- Teens
('2 Chronicles', 14, 'teens', 1, 'What religious reforms did Asa carry out in the land during his years of peace?', 'He removed the foreign altars and high places, broke the images, and cut down the groves', 'He rebuilt the temple walls and repaired the bronze altar', 'He drove out all the foreign traders from Jerusalem', 'He reinstated the Passover feast that had been neglected', 'a', '2 Chronicles 14:3 — "For he took away the altars of the strange gods, and the high places, and brake down the images, and cut down the groves."'),
('2 Chronicles', 14, 'teens', 2, 'What did Asa tell Judah to seek and do during the years of peace?', 'Seek the LORD God of their fathers and do the law and the commandment', 'Build fortified cities and store up supplies', 'Make alliances with neighboring nations', 'Increase their army and train more soldiers', 'a', '2 Chronicles 14:4 — "And commanded Judah to seek the LORD God of their fathers, and to do the law and the commandment."'),
('2 Chronicles', 14, 'teens', 3, 'What did Asa build during the years of peace, and what did he say to Judah about it?', 'Fenced cities with walls, towers, gates, and bars; he said the land was theirs because they had sought the LORD', 'A new palace larger than Solomon''s', 'A fleet of ships for trade', 'A great road connecting all the cities of Judah', 'a', '2 Chronicles 14:7 — "Therefore he said unto Judah, Let us build these cities, and make about them walls, and towers, gates, and bars, while the land is yet before us; because we have sought the LORD our God."'),
('2 Chronicles', 14, 'teens', 4, 'Where did the battle between Asa and Zerah the Ethiopian take place?', 'In the valley of Zephathah at Mareshah', 'At the Jordan River crossing', 'Near Jerusalem at the Kidron valley', 'At Megiddo in the plain of Jezreel', 'a', '2 Chronicles 14:10 — "Then Asa went out against him, and they set the battle in array in the valley of Zephathah at Mareshah."'),
('2 Chronicles', 14, 'teens', 5, 'What did God do in response to Asa''s prayer against Zerah?', 'The LORD smote the Ethiopians before Asa and before Judah and they fled', 'He sent fire from heaven to consume their chariots', 'He caused an earthquake to swallow the enemy army', 'He sent hornets to drive away the Ethiopian army', 'a', '2 Chronicles 14:12 — "So the LORD smote the Ethiopians before Asa, and before Judah; and the Ethiopians fled."'),
-- Adults
('2 Chronicles', 14, 'adults', 1, 'What was the precise size of Asa''s army when he faced Zerah the Ethiopian?', 'Three hundred thousand men from Judah bearing shields and spears, and two hundred and fourscore thousand from Benjamin bearing shields and drawing bows', 'Five hundred thousand men from all the tribes', 'Two hundred thousand chosen warriors', 'Four hundred thousand men armed with swords', 'a', '2 Chronicles 14:8 — "And Asa had an army of men that bare targets and spears, out of Judah three hundred thousand; and out of Benjamin...two hundred and fourscore thousand."'),
('2 Chronicles', 14, 'adults', 2, 'What was the full content of Asa''s prayer before battle, and what theological principle did it express?', 'He said it is nothing for the LORD to help with many or with those of no power, and asked God to rest on them so that men would not prevail against God', 'He asked for a sign before committing to battle', 'He recited all of God''s past victories for Israel', 'He promised to build a new altar if God gave victory', 'a', '2 Chronicles 14:11 — "LORD, it is nothing with thee to help, whether with many, or with them that have no power: help us, O LORD our God; for we rest on thee, and in thy name we go against this multitude."'),
('2 Chronicles', 14, 'adults', 3, 'What cities were spoiled after the Ethiopian defeat, and what was found there?', 'They smote all the cities round about Gerar for the fear of the LORD was upon them, and they spoiled all the cities and carried away much spoil', 'Only Gerar itself was spoiled and emptied', 'They took three specific named cities along the trade route', 'They seized Egyptian trading posts along the Nile delta', 'a', '2 Chronicles 14:14 — "And they smote all the cities round about Gerar; for the fear of the LORD came upon them: and they spoiled all the cities; for there was exceeding much spoil in them."'),
('2 Chronicles', 14, 'adults', 4, 'What livestock did Judah carry away from the battle''s aftermath?', 'Sheep and camels in abundance', 'Horses and mules from the Ethiopian cavalry', 'Cattle and donkeys for agriculture', 'Goats and oxen as temple offerings', 'a', '2 Chronicles 14:15 — "They smote also the tents of cattle, and carried away sheep and camels in abundance, and returned to Jerusalem."'),
('2 Chronicles', 14, 'adults', 5, 'How does the Chronicler''s account of Asa''s reign in chapter 14 establish a pattern for his overall theology of history?', 'Seeking God brings peace and victory; Asa''s prosperity is explicitly linked to his obedience, establishing a retribution theology the Chronicler applies throughout', 'The Chronicler shows that military strength alone determines outcome', 'The Chronicler demonstrates that alliances with foreign powers are always blessed', 'The Chronicler indicates that reform is only needed after military defeat', 'a', '2 Chronicles 14:7 — "Because we have sought the LORD our God, we have sought him, and he hath given us rest on every side."'),
('2 Chronicles', 14, 'adults', 6, 'What does the description of Asa''s fortified cities reveal about his administrative capabilities?', 'He was a strategic builder who took advantage of peace to strengthen Judah''s defenses with walls, towers, gates, and bars — demonstrating prudent governance', 'He relied entirely on God and built nothing for national defense', 'His building projects were condemned by the prophets as a lack of faith', 'He copied Solomon''s building projects without original strategy', 'a', '2 Chronicles 14:6-7 — "And he built fenced cities in Judah: for the land had rest...and he had no war in those years."'),
('2 Chronicles', 14, 'adults', 7, 'What does the phrase "the LORD thy God is with thee" imply about the relationship between divine presence and human seeking in this chapter?', 'The divine presence is conditioned upon and responsive to wholehearted seeking — "because thou hast sought the LORD thy God, he is with thee"', 'God''s presence is unconditional regardless of human behavior', 'God''s presence was guaranteed only to the Davidic kings', 'The phrase refers only to military victory and has no spiritual dimension', 'a', '2 Chronicles 15:2 — "The LORD is with you, while ye be with him; and if ye seek him, he will be found of you."'),
('2 Chronicles', 14, 'adults', 8, 'What does Zerah''s force of a million men and three hundred chariots against Asa''s 580,000 suggest about the theological point the Chronicler is making?', 'That numerical and material superiority are irrelevant when God fights for those who trust him — Asa''s smaller force defeats the larger through prayer', 'That Judah had grown complacent and needed a wake-up call', 'That God only helps when the odds are even', 'That Asa''s military reforms had secretly made Judah stronger than the numbers suggest', 'a', '2 Chronicles 14:11 — "LORD, it is nothing with thee to help, whether with many, or with them that have no power," making the disparity in size the very point.');

-- ═══ 2 Chronicles Chapter 15 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 15, 'kids', 1, 'What prophet came to King Asa with a message from God?', 'Azariah the son of Oded', 'Elijah the Tishbite', 'Isaiah the son of Amoz', 'Jeremiah the son of Hilkiah', 'a', '2 Chronicles 15:1 — "And the Spirit of God came upon Azariah the son of Oded."'),
('2 Chronicles', 15, 'kids', 2, 'What did Azariah tell Asa that God would do if they sought him?', 'He would be found by them', 'He would give them gold and silver', 'He would destroy all their enemies', 'He would give them a long life', 'a', '2 Chronicles 15:2 — "The LORD is with you, while ye be with him; and if ye seek him, he will be found of you."'),
('2 Chronicles', 15, 'kids', 3, 'What did Asa do to his grandmother Maachah because of her idol?', 'He removed her from being queen and destroyed her idol', 'He sent her to live in another country', 'He put her in prison for her sin', 'He made her pay a fine for the idol', 'a', '2 Chronicles 15:16 — "And also concerning Maachah the mother of Asa the king, he removed her from being queen, because she had made an idol in a grove."'),
-- Teens
('2 Chronicles', 15, 'teens', 1, 'What warning did Azariah give about forsaking God based on Israel''s past history?', 'If they forsook God he would forsake them, and for a long time Israel had been without the true God, without a teaching priest, and without law', 'God would send a foreign king to conquer them', 'The land would suffer drought and famine for seven years', 'The Davidic dynasty would come to an end', 'a', '2 Chronicles 15:2-3 — "But if ye forsake him, he will forsake you...Now for a long season Israel hath been without the true God, and without a teaching priest, and without law."'),
('2 Chronicles', 15, 'teens', 2, 'What did Asa do to the temple as a result of Azariah''s prophecy?', 'He put away the abominable idols from all the land of Judah and Benjamin and renewed the altar of the LORD', 'He tore down and rebuilt the entire temple', 'He hired new priests to replace the corrupt ones', 'He moved the ark of the covenant back to its original position', 'a', '2 Chronicles 15:8 — "And when Asa heard these words...he took courage, and put away the abominable idols out of all the land of Judah and Benjamin...and renewed the altar of the LORD."'),
('2 Chronicles', 15, 'teens', 3, 'Who gathered to Jerusalem for the great assembly and covenant renewal under Asa?', 'People from Judah, Benjamin, and strangers from Ephraim, Manasseh, and Simeon who had fallen to him out of Israel', 'Only the people of Judah and Benjamin', 'Representatives from all twelve tribes equally', 'Levites from all parts of the country', 'a', '2 Chronicles 15:9 — "And he gathered all Judah and Benjamin, and the strangers with them out of Ephraim and Manasseh, and out of Simeon: for they fell to him out of Israel in abundance, when they saw that the LORD his God was with him."'),
('2 Chronicles', 15, 'teens', 4, 'What happened at the great assembly — what sacrifices were offered?', 'Seven hundred oxen and seven thousand sheep from the spoil they had brought', 'Three thousand bulls and ten thousand sheep', 'One thousand oxen and five thousand sheep as firstfruits', 'The usual daily offerings plus a hundred special sacrifices', 'a', '2 Chronicles 15:11 — "And they offered unto the LORD the same time, of the spoil which they had brought, seven hundred oxen and seven thousand sheep."'),
('2 Chronicles', 15, 'teens', 5, 'What was the penalty established in the covenant renewal for anyone who would not seek the LORD God of Israel?', 'He should be put to death, whether small or great, man or woman', 'He should be banished from the land', 'He should pay a heavy fine to the temple', 'He should lose all his property', 'a', '2 Chronicles 15:13 — "That whosoever would not seek the LORD God of Israel should be put to death, whether small or great, whether man or woman."'),
-- Adults
('2 Chronicles', 15, 'adults', 1, 'What specific idol did Maachah make that caused Asa to remove her as queen mother, and what did he do to it?', 'She made an idol in a grove and Asa cut down her idol and stamped it and burnt it at the brook Kidron', 'She set up a golden calf and Asa melted it down', 'She built a high place for Baal and Asa demolished it', 'She brought Asherah poles into the temple and Asa removed them', 'a', '2 Chronicles 15:16 — "He removed her from being queen, because she had made an idol in a grove: and Asa cut down her idol, and stamped it, and burnt it at the brook Kidron."'),
('2 Chronicles', 15, 'adults', 2, 'What remained even after Asa''s reforms, and what does this reveal about the limits of his reformation?', 'The high places were not taken away out of Israel, though Asa''s heart was perfect all his days', 'Asa failed to remove the golden calves from Bethel and Dan', 'The Asherah poles remained in Samaria throughout his reign', 'The foreign priests were not expelled despite the reform decree', 'a', '2 Chronicles 15:17 — "But the high places were not taken away out of Israel: nevertheless the heart of Asa was perfect all his days."'),
('2 Chronicles', 15, 'adults', 3, 'What did Asa bring into the house of God, and from where did these things come?', 'The silver and gold and vessels that he and his father had dedicated', 'Spoil from the Ethiopian war including captured weapons', 'Tribute payments from all the nations around Judah', 'New furnishings crafted by the artisans of Tyre', 'a', '2 Chronicles 15:18 — "And he brought into the house of God the things that his father had dedicated, and that he himself had dedicated, silver, and gold, and vessels."'),
('2 Chronicles', 15, 'adults', 4, 'What does the phrase "they sware unto the LORD with a loud voice, and with shouting, and with trumpets, and with cornets" reveal about this covenant renewal ceremony?', 'It was a full national liturgical event combining solemn vow with joyful public worship — the community''s wholehearted commitment expressed through both word and music', 'It was a military victory celebration that included a vow', 'It was a private ceremony for the priests and Levites only', 'It was modeled on the Sinai covenant ceremony described in Exodus', 'a', '2 Chronicles 15:14 — "And they sware unto the LORD with a loud voice, and with shouting, and with trumpets, and with cornets."'),
('2 Chronicles', 15, 'adults', 5, 'What was the result of the covenant renewal — what did God give Judah?', 'The LORD gave them rest round about', 'God sent rain after three years of drought', 'God doubled their harvests for ten years', 'God gave them victory over three surrounding nations', 'a', '2 Chronicles 15:15 — "And all Judah rejoiced at the oath: for they had sworn with all their heart, and sought him with their whole desire; and he was found of them: and the LORD gave them rest round about."'),
('2 Chronicles', 15, 'adults', 6, 'How long had it been since there was "no peace to him that went out, nor to him that came in" according to Azariah''s historical review?', 'During those ancient troubled times when nation was destroyed of nation and city of city, before Asa''s time of peace', 'During the reign of Rehoboam specifically', 'For the forty years of wilderness wandering', 'During the period of the judges before the monarchy', 'a', '2 Chronicles 15:5-6 — "And in those times there was no peace to him that went out, nor to him that came in, but great vexations were upon all the inhabitants of the countries. And nation was destroyed of nation, and city of city."'),
('2 Chronicles', 15, 'adults', 7, 'What year of Asa''s reign did the great assembly and covenant renewal take place?', 'The fifteenth year of Asa''s reign', 'The tenth year of his reign', 'The twenty-fifth year of his reign', 'The first year of his reign', 'a', '2 Chronicles 15:10 — "So they gathered themselves together at Jerusalem in the third month, in the fifteenth year of the reign of Asa."'),
('2 Chronicles', 15, 'adults', 8, 'What does Azariah''s statement "if ye seek him, he will be found of you; but if ye forsake him, he will forsake you" establish as a governing principle throughout Chronicles?', 'A conditional covenant relationship: divine blessing and presence are contingent on human seeking and faithfulness, not merely ethnic or dynastic privilege', 'An unconditional promise based solely on David''s covenant', 'A principle that applies only to kings, not ordinary Israelites', 'A temporary arrangement until the building of the temple', 'a', '2 Chronicles 15:2 — "The LORD is with you, while ye be with him; and if ye seek him, he will be found of you; but if ye forsake him, he will forsake you."');

-- ═══ 2 Chronicles Chapter 16 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 16, 'kids', 1, 'Instead of trusting God when Baasha king of Israel threatened him, what did Asa do?', 'He sent silver and gold to the king of Syria for help', 'He prayed and fasted for three days', 'He built a bigger army for Judah', 'He asked the priests what to do', 'a', '2 Chronicles 16:2-3 — "Then Asa brought out silver and gold out of the treasures of the house of the LORD...and sent to Benhadad king of Syria."'),
('2 Chronicles', 16, 'kids', 2, 'What prophet came to rebuke Asa for trusting Syria instead of God?', 'Hanani the seer', 'Elijah the Tishbite', 'Nathan the prophet', 'Micaiah the son of Imlah', 'a', '2 Chronicles 16:7 — "And at that time Hanani the seer came to Asa king of Judah."'),
('2 Chronicles', 16, 'kids', 3, 'What sickness did God send upon Asa near the end of his life?', 'A disease in his feet', 'Blindness in both eyes', 'Leprosy on his hands', 'Fever that would not go away', 'a', '2 Chronicles 16:12 — "And Asa in the thirty and ninth year of his reign was diseased in his feet."'),
-- Teens
('2 Chronicles', 16, 'teens', 1, 'What had God done for Asa earlier that Hanani referenced to rebuke his failure to trust?', 'God had delivered the Ethiopians and the Lubims and a great host into his hand because he relied on the LORD', 'God had sent prophets to warn him about Syria three times', 'God had blessed his building projects abundantly', 'God had made him the most powerful king since Solomon', 'a', '2 Chronicles 16:8 — "Were not the Ethiopians and the Lubims a huge host, with very many chariots and horsemen? yet, because thou didst rely on the LORD, he delivered them into thine hand."'),
('2 Chronicles', 16, 'teens', 2, 'What did Hanani say about those whose heart is perfect toward God?', 'The eyes of the LORD run to and fro throughout the whole earth to show himself strong on their behalf', 'God will give them rest from all their enemies', 'Their children will reign after them in peace', 'God will send angels to guard them', 'a', '2 Chronicles 16:9 — "For the eyes of the LORD run to and fro throughout the whole earth, to shew himself strong in the behalf of them whose heart is perfect toward him."'),
('2 Chronicles', 16, 'teens', 3, 'What did Asa do to Hanani after the prophet rebuked him?', 'He put him in prison and oppressed some of the people at the same time', 'He sent him away from Jerusalem in exile', 'He fined him a large amount of silver', 'He accepted the rebuke and repented publicly', 'a', '2 Chronicles 16:10 — "Then Asa was wroth with the seer, and put him in a prison house; for he was in a rage with him because of this thing. And Asa oppressed some of the people the same time."'),
('2 Chronicles', 16, 'teens', 4, 'What did Asa do in his illness that showed his continued failure to trust God?', 'He sought not the LORD but only the physicians', 'He offered sacrifices to foreign gods', 'He refused to let the Levites pray for him', 'He fled to Egypt to find medicine', 'a', '2 Chronicles 16:12 — "And Asa in the thirty and ninth year of his reign was diseased in his feet, until his disease was exceeding great: yet in his disease he sought not to the LORD, but to the physicians."'),
('2 Chronicles', 16, 'teens', 5, 'What did Hanani say would happen to Asa because he relied on Syria rather than on God?', 'From henceforth he would have wars', 'His kingdom would be divided among his sons', 'Syria would eventually conquer Jerusalem', 'The tribute he paid would bankrupt the kingdom', 'a', '2 Chronicles 16:9 — "Herein thou hast done foolishly: therefore from henceforth thou shalt have wars."'),
-- Adults
('2 Chronicles', 16, 'adults', 1, 'What was the political situation that led Asa to seek Syrian help — what had Baasha done?', 'Baasha built Ramah to prevent anyone going out or coming in to Asa king of Judah', 'Baasha invaded southern Judah and captured three cities', 'Baasha made an alliance with Egypt against Judah', 'Baasha cut off Judah''s access to the sea ports', 'a', '2 Chronicles 16:1 — "In the six and thirtieth year of the reign of Asa Baasha king of Israel came up against Judah, and built Ramah, to the intent that he might let none go out or come in to Asa king of Judah."'),
('2 Chronicles', 16, 'adults', 2, 'What was the precise agreement Asa made with Benhadad of Syria and what did it involve breaking?', 'He sent silver and gold from the treasures of the house of the LORD and the king''s house and asked Benhadad to break his league with Baasha', 'He gave Syrian merchants trading rights in Jerusalem', 'He surrendered five cities to Syria in exchange for military help', 'He gave Benhadad hostages from the royal family', 'a', '2 Chronicles 16:3 — "There is a league between me and thee, as there was between my father and thy father: behold, I have sent thee silver and gold; go, break thy league with Baasha king of Israel."'),
('2 Chronicles', 16, 'adults', 3, 'What did Benhadad do militarily after receiving Asa''s silver and gold?', 'He smote Ijon, Dan, Abelmaim, and the store cities of Naphtali', 'He attacked Samaria and forced Baasha to withdraw', 'He occupied the Jordan valley as a buffer zone', 'He besieged Tirzah, capital of northern Israel', 'a', '2 Chronicles 16:4 — "And Benhadad hearkened unto king Asa, and sent the captains of his armies against the cities of Israel; and they smote Ijon, and Dan, and Abelmaim, and all the store cities of Naphtali."'),
('2 Chronicles', 16, 'adults', 4, 'What did Asa do with the stone and timber Baasha had been using to build Ramah?', 'He took them and built Geba and Mizpah with them', 'He destroyed all of it so Baasha could not finish', 'He used it to repair the walls of Jerusalem', 'He stored the materials in the temple precincts', 'a', '2 Chronicles 16:6 — "Then Asa the king took all Judah; and they carried away the stones of Ramah, and the timber thereof, wherewith Baasha was building; and he built therewith Geba and Mizpah."'),
('2 Chronicles', 16, 'adults', 5, 'What contrast does Hanani draw between what Asa could have had versus what he now has?', 'Had he relied on God the host of Syria would have been delivered into his hand, but now he has wars instead', 'He could have had peace with all nations but now only Syria is his enemy', 'He could have been wealthier than Solomon but now faces poverty', 'He could have conquered Baasha completely but now Baasha is stronger', 'a', '2 Chronicles 16:7 — "Because thou hast relied on the king of Syria, and not relied on the LORD thy God, therefore is the host of the king of Syria escaped out of thine hand."'),
('2 Chronicles', 16, 'adults', 6, 'What was the manner of Asa''s burial and the honors given to him at his death?', 'He was buried in his own sepulchres in the city of David and they laid him on a bed of spices with a very great burning of fire made in his honour', 'He was buried without ceremony because of his failures', 'He was buried in the valley of Kidron outside the city', 'He was buried alongside his father Abijah in a shared tomb', 'a', '2 Chronicles 16:14 — "And they buried him in his own sepulchres, which he had made for himself in the city of David, and laid him in the bed which was filled with sweet odours and divers kinds of spices prepared by the apothecaries'' art: and they made a very great burning for him."'),
('2 Chronicles', 16, 'adults', 7, 'How does the structure of Asa''s reign in chapters 14-16 demonstrate the Chronicler''s theological pattern of testing?', 'Asa''s early seeking of God brings victory and peace; his later failure to seek God brings prophet rebuke, war, and disease — showing blessing follows faithfulness and failure follows self-reliance', 'The Chronicler shows Asa as uniformly righteous throughout his reign', 'The Chronicler focuses only on the political failures without theological commentary', 'The Chronicler blames Baasha for all of Asa''s problems', 'a', '2 Chronicles 14:11 compared to 16:7 — the same verb "rely on the LORD" used positively in ch.14 and negatively in ch.16 creates a deliberate contrast.'),
('2 Chronicles', 16, 'adults', 8, 'What does Asa''s imprisonment of Hanani suggest about the spiritual decline of his later years?', 'Asa had moved from a king who sought God and accepted divine guidance to one who silenced prophetic critique, showing hardening of heart — a pattern the Chronicler shows leads to judgment', 'Asa was testing the prophet''s credentials before accepting his message', 'The imprisonment was later rescinded showing Asa''s eventual repentance', 'Hanani had spoken presumptuously without proper credentials', 'a', '2 Chronicles 16:10 — "Then Asa was wroth with the seer, and put him in a prison house; for he was in a rage with him," contrasting with his earlier reception of Azariah''s prophecy in chapter 15.');

-- ═══ 2 Chronicles Chapter 17 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 17, 'kids', 1, 'Who became king of Judah after Asa?', 'Jehoshaphat his son', 'Joash his nephew', 'Abijah his brother', 'Uzziah his grandson', 'a', '2 Chronicles 17:1 — "And Jehoshaphat his son reigned in his stead, and strengthened himself against Israel."'),
('2 Chronicles', 17, 'kids', 2, 'What did Jehoshaphat send throughout all the cities of Judah to teach the people?', 'Princes and Levites and priests with the book of the law of the LORD', 'Soldiers to collect taxes for the temple', 'Builders to repair the city walls', 'Singers to lead worship in every town', 'a', '2 Chronicles 17:7-9 — "He sent to his princes...And with them he sent Levites...And they taught in Judah, and had the book of the law of the LORD with them."'),
('2 Chronicles', 17, 'kids', 3, 'Why did God establish Jehoshaphat''s kingdom?', 'Because he walked in the first ways of his father David and sought the LORD', 'Because he had the biggest army in all of Judah', 'Because he rebuilt the temple from the ground up', 'Because he made peace with all the surrounding nations', 'a', '2 Chronicles 17:3-4 — "And the LORD was with Jehoshaphat, because he walked in the first ways of his father David...but sought to the LORD God of his father."'),
-- Teens
('2 Chronicles', 17, 'teens', 1, 'What did Jehoshaphat remove from Judah in his religious reforms?', 'The high places and groves out of Judah', 'All the foreign merchants from Jerusalem', 'The Baal temples that Asa had not destroyed', 'The non-Levitical priests from the temple service', 'a', '2 Chronicles 17:6 — "And his heart was lifted up in the ways of the LORD: moreover he took away the high places and groves out of Judah."'),
('2 Chronicles', 17, 'teens', 2, 'What was the purpose of sending the teaching mission throughout Judah in the third year of Jehoshaphat''s reign?', 'To teach the people the book of the law of the LORD in all the cities of Judah', 'To collect the temple tax from every household', 'To recruit soldiers for the expanding army', 'To register all the priests and Levites in a census', 'a', '2 Chronicles 17:9 — "And they taught in Judah, and had the book of the law of the LORD with them, and went about throughout all the cities of Judah, and taught the people."'),
('2 Chronicles', 17, 'teens', 3, 'What effect did Jehoshaphat''s early reign have on the surrounding nations?', 'The fear of the LORD fell upon all the kingdoms of the lands round about Judah and they made no war against him', 'They all paid tribute to Jehoshaphat after his first military campaign', 'They formed an alliance against him but were defeated', 'They sent ambassadors asking to learn about Israel''s God', 'a', '2 Chronicles 17:10 — "And the fear of the LORD fell upon all the kingdoms of the lands that were round about Judah, so that they made no war against Jehoshaphat."'),
('2 Chronicles', 17, 'teens', 4, 'What did the Philistines and Arabians bring to Jehoshaphat as tribute?', 'The Philistines brought presents and silver and the Arabians brought him rams and he-goats', 'Both nations sent cedar timber and spices', 'Gold and precious stones from their mines', 'Grain and oil from their harvests', 'a', '2 Chronicles 17:11 — "Also some of the Philistines brought Jehoshaphat presents, and tribute silver; and the Arabians brought him flocks, seven thousand and seven hundred rams, and seven thousand and seven hundred he goats."'),
('2 Chronicles', 17, 'teens', 5, 'How large was Jehoshaphat''s army according to the detailed military census in this chapter?', 'Over one million forty thousand armed men from Judah and Benjamin combined under five commanders', 'Five hundred thousand men in total', 'Three hundred thousand chosen warriors', 'Eight hundred thousand men ready for battle', 'a', '2 Chronicles 17:14-18 — The five commanders'' armies total: 300,000 + 280,000 + 200,000 + 200,000 + 180,000 = 1,160,000 men.'),
-- Adults
('2 Chronicles', 17, 'adults', 1, 'What was the specific contrast the Chronicler drew between Jehoshaphat and his father Asa in terms of religious practice?', 'Jehoshaphat walked in the first ways of his father David and sought not Baalim but the LORD God of his father, not walking after Israel''s doings', 'Jehoshaphat completed the reforms Asa had begun but failed to finish', 'Jehoshaphat surpassed Asa by removing all the high places', 'Jehoshaphat restored the Levitical music that Asa had neglected', 'a', '2 Chronicles 17:3-4 — "He walked in the first ways of his father David...For he sought to the LORD God of his father, and walked in his commandments, and not after the doings of Israel."'),
('2 Chronicles', 17, 'adults', 2, 'Who were the five princes sent on the teaching mission and how many Levites and priests accompanied them?', 'Five princes (Benhail, Obadiah, Zechariah, Nethaneel, Michaiah) with nine Levites and two priests — Elishama and Jehoram', 'Three princes with twelve Levites and four priests', 'Seven princes with twenty Levites and the high priest', 'Ten princes with thirty Levites and six priests', 'a', '2 Chronicles 17:7-8 — "Also in the third year of his reign he sent to his princes, even to Benhail, and to Obadiah, and to Zechariah, and to Nethaneel, and to Michaiah, to teach in the cities of Judah. And with them he sent Levites...and with them Elishama and Jehoram, priests."'),
('2 Chronicles', 17, 'adults', 3, 'What does the sending of the Book of the Law with the teaching mission suggest about Jehoshaphat''s view of Torah in national life?', 'He regarded the written law as the authoritative basis for national reform — teaching Scripture systematically to all citizens, not just religious specialists', 'The book was sent primarily for the priests to study privately', 'The law was used mainly for legal disputes and property cases', 'The teaching mission was primarily about temple rituals and sacrifices', 'a', '2 Chronicles 17:9 — "And they taught in Judah, and had the book of the law of the LORD with them, and went about throughout all the cities of Judah, and taught the people."'),
('2 Chronicles', 17, 'adults', 4, 'What was the administrative structure of Jehoshaphat''s military, and what does the detail reveal about his reign?', 'Five commanders over five divisions from Judah (Adnah, Jehohanan, Amasiah) and Benjamin (Eliada, Jehozabad) with specific troop numbers for each — showing a well-organized professional military', 'A single general over an undifferentiated mass army', 'A rotating command system changing every three years', 'Tribal militias without central command structure', 'a', '2 Chronicles 17:14-18 — the five named commanders with precise troop totals shows systematic military organization.'),
('2 Chronicles', 17, 'adults', 5, 'What did it mean that Amasiah "willingly offered himself unto the LORD" according to verse 16?', 'He volunteered his service as an act of devotion rather than being conscripted — indicating a class of dedicated military volunteers within Jehoshaphat''s forces', 'He offered sacrifices at the temple before each battle', 'He pledged his personal wealth to fund the army', 'He had taken a Nazirite vow of military dedication', 'a', '2 Chronicles 17:16 — "And next him was Amasiah the son of Zichri, who willingly offered himself unto the LORD; and with him two hundred thousand mighty men of valour."'),
('2 Chronicles', 17, 'adults', 6, 'What was the theological significance of the fear of the LORD falling on surrounding nations rather than Jehoshaphat winning military campaigns?', 'God protected Judah supernaturally through his own reputation, making wars unnecessary — showing divine sovereignty working through awe rather than requiring human military action', 'The surrounding nations were simply too weak to challenge Judah', 'Jehoshaphat''s diplomacy rather than God''s action kept the peace', 'The peace was fragile and would soon end', 'a', '2 Chronicles 17:10 — "And the fear of the LORD fell upon all the kingdoms of the lands that were round about Judah, so that they made no war against Jehoshaphat."'),
('2 Chronicles', 17, 'adults', 7, 'How does the Chronicler''s portrait of Jehoshaphat in chapter 17 set up the contrast with his alliance with Ahab in chapter 18?', 'Chapter 17 establishes Jehoshaphat as a faithful, prosperous king separated from Israel''s corruption — making his alliance with the apostate Ahab in chapter 18 a surprising and theologically significant failure', 'Chapter 17 shows Jehoshaphat was already inclined toward compromise', 'The Chronicler presents chapters 17-18 as unrelated events in Jehoshaphat''s reign', 'Chapter 17 is included only for its military census data', 'a', '2 Chronicles 17:6 — "His heart was lifted up in the ways of the LORD," contrasting sharply with his behavior in 18:3: "I am as thou art, and my people as thy people."'),
('2 Chronicles', 17, 'adults', 8, 'What does it mean that Jehoshaphat''s heart was "lifted up in the ways of the LORD" — how does this phrase function in Chronicles?', 'It is a positive description meaning his heart was exalted by and directed toward God''s ways, indicating wholehearted devotion — contrasting with kings whose hearts were lifted up in pride against God', 'It is a warning sign of approaching pride and failure', 'It refers specifically to his elevation of temple worship', 'It is a formula meaning he achieved military success', 'a', '2 Chronicles 17:6 — "And his heart was lifted up in the ways of the LORD: moreover he took away the high places and groves out of Judah," showing the phrase as motivational for reform.');

-- ═══ 2 Chronicles Chapter 18 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 18, 'kids', 1, 'Which king of Israel did Jehoshaphat make an alliance with by marriage?', 'Ahab', 'Jeroboam', 'Baasha', 'Omri', 'a', '2 Chronicles 18:1 — "Now Jehoshaphat had riches and honour in abundance, and joined affinity with Ahab."'),
('2 Chronicles', 18, 'kids', 2, 'What did the prophet Micaiah say he would only speak?', 'Whatever God said to him', 'Only good things about the king', 'The words of the other prophets', 'Nothing at all to the king', 'a', '2 Chronicles 18:13 — "And Micaiah said, As the LORD liveth, even what my God saith, that will I speak."'),
('2 Chronicles', 18, 'kids', 3, 'What happened to Ahab in the battle against Syria even though he disguised himself?', 'A man shot an arrow at random and it struck him between the joints of his armour', 'He was captured by the Syrian king', 'He fell off his chariot and was trampled', 'He was killed by one of his own soldiers by mistake', 'a', '2 Chronicles 18:33 — "And a certain man drew a bow at a venture, and smote the king of Israel between the joints of the harness."'),
-- Teens
('2 Chronicles', 18, 'teens', 1, 'What did the four hundred prophets of Ahab tell him about going to battle at Ramoth-gilead?', 'Go up, for God will deliver it into the king''s hand', 'Do not go — you will be defeated and killed', 'Wait for a sign from heaven before attacking', 'Make peace with Syria first', 'a', '2 Chronicles 18:5 — "And the prophets said, Go up; for God will deliver it into the king''s hand."'),
('2 Chronicles', 18, 'teens', 2, 'What vision did Micaiah describe of Israel after the battle?', 'All Israel scattered upon the mountains as sheep that have no shepherd', 'Jerusalem in flames and the temple destroyed', 'The king''s body lying in the valley of Jezreel', 'The armies of Israel fleeing to Egypt', 'a', '2 Chronicles 18:16 — "Then he said, I did see all Israel scattered upon the mountains, as sheep that have no shepherd."'),
('2 Chronicles', 18, 'teens', 3, 'What did Micaiah see in his vision of the heavenly court regarding the false prophets?', 'A lying spirit in the mouth of all Ahab''s prophets sent by God to entice Ahab', 'Angels of God filling the prophets with confusion', 'The spirit of Jezebel controlling the court prophets', 'Satan himself speaking through the false prophets', 'a', '2 Chronicles 18:21-22 — "And the LORD said unto him, Wherewith? And he said, I will go out, and be a lying spirit in the mouth of all his prophets...the LORD hath put a lying spirit in the mouth of these thy prophets."'),
('2 Chronicles', 18, 'teens', 4, 'What did Zedekiah son of Chenaanah do to Micaiah after his prophecy?', 'He smote him on the cheek and asked which way the spirit of the LORD went', 'He called him a false prophet and demanded his execution', 'He challenged him to a public debate before the king', 'He pushed him out of the king''s presence', 'a', '2 Chronicles 18:23 — "Then Zedekiah the son of Chenaanah came near, and smote Micaiah upon the cheek, and said, Which way went the Spirit of the LORD from me to speak unto thee?"'),
('2 Chronicles', 18, 'teens', 5, 'What was Ahab''s strategy with Jehoshaphat for the battle — what disguise did they use?', 'Ahab disguised himself but told Jehoshaphat to wear his royal robes', 'Both kings wore disguises so the enemy could not target them', 'Jehoshaphat led the main army while Ahab commanded from the rear', 'Ahab dressed as a common soldier and gave Jehoshaphat his chariot', 'a', '2 Chronicles 18:29 — "And the king of Israel said unto Jehoshaphat, I will disguise myself, and will enter into the battle; but put thou on thy robes."'),
-- Adults
('2 Chronicles', 18, 'adults', 1, 'What was the occasion that brought Jehoshaphat and Ahab together, and what did Ahab propose?', 'Ahab held a great feast for Jehoshaphat and proposed they go together to recover Ramoth-gilead from Syria', 'Jehoshaphat visited Samaria to negotiate a trade agreement', 'Ahab came to Jerusalem seeking military assistance against Moab', 'Both kings gathered to divide the spoil from a previous battle', 'a', '2 Chronicles 18:2 — "And after certain years he went down to Ahab to Samaria. And Ahab killed sheep and oxen for him in abundance, and for the people that he had with him, and persuaded him to go up with him to Ramoth-gilead."'),
('2 Chronicles', 18, 'adults', 2, 'What was the precise content of Micaiah''s first ironic answer to Ahab, and why did Ahab not believe it?', 'He said "Go ye up, and prosper" ironically — Ahab recognized this as sarcasm matching what the other prophets said and demanded he speak the truth', 'Micaiah refused to answer at first', 'Micaiah predicted defeat from the beginning without irony', 'Micaiah spoke in parable and Ahab could not understand', 'a', '2 Chronicles 18:14-15 — "And when he was come to the king, the king said unto him, Micaiah, shall we go to Ramoth-gilead to battle?...And he said, Go ye up, and prosper...And the king said to him, How many times shall I adjure thee that thou say nothing but the truth to me?"'),
('2 Chronicles', 18, 'adults', 3, 'What specifically was Micaiah''s message from the LORD about Ahab''s fate?', 'The LORD said these have no master, let them return every man to his house in peace — indicating Ahab would die in battle', 'God said Ahab would be wounded but recover if he repented', 'The LORD told Micaiah Ahab would be captured and ransomed', 'God decreed Ahab would reign ten more years as punishment for Israel', 'a', '2 Chronicles 18:16 — "Then he said, I did see all Israel scattered upon the mountains, as sheep that have no shepherd: and the LORD said, These have no master; let them return therefore every man to his house in peace."'),
('2 Chronicles', 18, 'adults', 4, 'What was Ahab''s response to Micaiah''s true prophecy, and what does it reveal about his character?', 'He had Micaiah put in prison on bread and water until his safe return — showing he rejected truth and trusted his own plans over God''s word', 'He cancelled the battle after hearing the prophecy', 'He publicly debated Micaiah''s credentials before the court', 'He sent Micaiah to Jehoshaphat for a second opinion', 'a', '2 Chronicles 18:25-26 — "Then the king of Israel said...Put this fellow in the prison, and feed him with bread of affliction and with water of affliction, until I return in peace."'),
('2 Chronicles', 18, 'adults', 5, 'What was Micaiah''s parting word that showed his confidence in his prophecy?', 'If thou certainly return in peace, then hath not the LORD spoken by me — affirming God''s word over the king''s optimism', 'He said he would be proven right within three days', 'He warned the prison guards they would be judged for obeying the king', 'He called the whole court to witness that his words were true', 'a', '2 Chronicles 18:27 — "And Micaiah said, If thou certainly return in peace, then hath not the LORD spoken by me. And he said, Hearken, all ye people."'),
('2 Chronicles', 18, 'adults', 6, 'Why did the Syrian commanders initially turn away from Jehoshaphat during the battle, and what saved him?', 'They thought he was the king of Israel but turned away when they realized he was not; Jehoshaphat cried out and the LORD helped him', 'Jehoshaphat''s bodyguards fought off the Syrian commanders successfully', 'God sent confusion into the Syrian camp at that moment', 'The Syrian king called off the attack to pursue Ahab instead', 'a', '2 Chronicles 18:31-32 — "And it came to pass...the captains of the chariots saw Jehoshaphat...Therefore they compassed about him to fight: but Jehoshaphat cried out, and the LORD helped him; and God moved them to depart from him."'),
('2 Chronicles', 18, 'adults', 7, 'How did Ahab die, and what happened to his blood?', 'He was wounded by the random arrow, propped up in his chariot until evening, and died at sunset; his blood was washed from the chariot in Samaria', 'He died immediately when struck and was carried from the field', 'He survived the battle but died of his wounds a week later', 'His blood was carried back to Ramoth-gilead for burial', 'a', '2 Chronicles 18:33-34 — "And a certain man drew a bow at a venture, and smote the king of Israel between the joints of the harness...and about the time of the sun going down he died."'),
('2 Chronicles', 18, 'adults', 8, 'What does the story of Micaiah in chapter 18 contribute to the Chronicler''s broader theology of prophecy and kingship?', 'It establishes that true prophets speak God''s word regardless of royal displeasure, and that ignoring true prophecy leads to death — Ahab''s fate becoming a warning for all kings who prefer flattery over truth', 'The story is included purely for its historical interest in synchronizing Judah and Israel''s histories', 'The Chronicler uses it to show that Jehoshaphat was innocent of Ahab''s sins', 'The story is primarily about the mechanics of divine deception in battle', 'a', '2 Chronicles 18:22 — "The LORD hath put a lying spirit in the mouth of these thy prophets, and the LORD hath spoken evil against thee," showing the deadly consequence of rejecting prophetic truth.');

-- ═══ 2 Chronicles Chapter 19 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 19, 'kids', 1, 'Who came to meet Jehoshaphat when he returned home from the battle with Ahab?', 'Jehu the son of Hanani the seer', 'Elijah the prophet', 'The high priest Amariah', 'His son Jehoram', 'a', '2 Chronicles 19:2 — "And Jehu the son of Hanani the seer went out to meet him."'),
('2 Chronicles', 19, 'kids', 2, 'What did Jehoshaphat do among the people after being rebuked, going from Beersheba to Mount Ephraim?', 'He brought them back unto the LORD God of their fathers', 'He collected taxes to rebuild the army', 'He built new cities in the wilderness', 'He made peace treaties with all the kings', 'a', '2 Chronicles 19:4 — "And Jehoshaphat dwelt at Jerusalem: and he went out again through the people from Beersheba to mount Ephraim, and brought them back unto the LORD God of their fathers."'),
('2 Chronicles', 19, 'kids', 3, 'What did Jehoshaphat tell the judges he appointed — whose judgment were they carrying out?', 'The LORD''s, not man''s', 'Their own best judgment', 'The elders'' and priests'' judgment', 'The king''s own orders', 'a', '2 Chronicles 19:6 — "And said to the judges, Take heed what ye do: for ye judge not for man, but for the LORD, who is with you in the judgment."'),
-- Teens
('2 Chronicles', 19, 'teens', 1, 'What rebuke did Jehu give Jehoshaphat about his alliance with Ahab?', 'Shouldest thou help the ungodly and love them that hate the LORD? — wrath of the LORD was upon him for this', 'He said Jehoshaphat had broken the covenant of salt with David''s house', 'He warned Jehoshaphat that Syria would now attack Judah', 'He told him the temple treasury must pay a penalty for the sin', 'a', '2 Chronicles 19:2 — "Shouldest thou help the ungodly, and love them that hate the LORD? therefore is wrath upon thee from before the LORD."'),
('2 Chronicles', 19, 'teens', 2, 'What saved Jehoshaphat from complete condemnation despite the rebuke?', 'There were good things found in him — he had taken away the groves from the land and prepared his heart to seek God', 'He immediately tore his garments and fasted for seven days', 'He paid a large offering to the temple to atone for his sin', 'He sent Jehu away without accepting the rebuke', 'a', '2 Chronicles 19:3 — "Nevertheless there are good things found in thee, in that thou hast taken away the groves out of the land, and hast prepared thine heart to seek God."'),
('2 Chronicles', 19, 'teens', 3, 'What specific warning about corruption did Jehoshaphat give the judges he appointed?', 'Take heed and do it, for there is no iniquity with the LORD, no respect of persons, and no taking of gifts', 'Never accept a bribe no matter how small', 'Always seek the king''s counsel before making major decisions', 'Record every judgment in writing for the king''s review', 'a', '2 Chronicles 19:7 — "Wherefore now let the fear of the LORD be upon you; take heed and do it: for there is no iniquity with the LORD our God, nor respect of persons, nor taking of gifts."'),
('2 Chronicles', 19, 'teens', 4, 'What court did Jehoshaphat set up in Jerusalem and who presided over it?', 'A court for controversies with Amariah the chief priest over matters of the LORD and Zebadiah over the king''s matters', 'A supreme court of twelve elders from each tribe', 'A military tribunal under the chief commander', 'A priestly council that met only on feast days', 'a', '2 Chronicles 19:8,11 — "Moreover in Jerusalem did Jehoshaphat set of the Levites, and of the priests...And, behold, Amariah the chief priest is over you in all matters of the LORD; and Zebadiah...for all the king''s matters."'),
('2 Chronicles', 19, 'teens', 5, 'What did Jehoshaphat charge those serving in the Jerusalem court to do as his closing exhortation?', 'Deal courageously and the LORD shall be with the good', 'Study the law day and night without ceasing', 'Teach the people the statutes every sabbath', 'Report all wrongdoers directly to the king', 'a', '2 Chronicles 19:11 — "Deal courageously, and the LORD shall be with the good."'),
-- Adults
('2 Chronicles', 19, 'adults', 1, 'What is the theological significance of Jehu''s rebuke — "shouldest thou help the ungodly, and love them that hate the LORD?" — for the Chronicler''s view of foreign alliances?', 'It establishes the principle that political alliances with those who reject God constitute a form of spiritual complicity — the Chronicler uses this to critique any entanglement that compromises covenant loyalty', 'The rebuke is purely political about treaty obligations to the house of David', 'Jehu is only concerned with Jehoshaphat''s military strategy', 'The rebuke is about specific terms of the alliance, not its existence', 'a', '2 Chronicles 19:2 — "Shouldest thou help the ungodly, and love them that hate the LORD?" establishing the principle of covenant-based foreign policy.'),
('2 Chronicles', 19, 'adults', 2, 'What does the phrase "good things found in thee" show about the Chronicler''s approach to moral evaluation of kings?', 'The Chronicler evaluates kings by their overall pattern of seeking God, allowing that even flawed kings retain genuine merit — avoiding simplistic all-or-nothing moral verdicts', 'The Chronicler applies a point-based system for righteousness', 'Good things only matter if they outweigh the bad deeds in number', 'The phrase is a diplomatic softening before the real condemnation', 'a', '2 Chronicles 19:3 — "Nevertheless there are good things found in thee," showing the Chronicler''s nuanced moral assessment of Jehoshaphat.'),
('2 Chronicles', 19, 'adults', 3, 'What does Jehoshaphat''s appointment of judges in every fortified city reveal about his administrative program?', 'He was implementing a systematic judicial reform extending accountability and fair legal process to every city of Judah — a major institutional achievement', 'He was primarily trying to increase tax revenue through better administration', 'The appointment was a ceremonial honor with no practical function', 'He was trying to reduce the power of the Levites by creating rival courts', 'a', '2 Chronicles 19:5 — "And he set judges in the land throughout all the fenced cities of Judah, city by city."'),
('2 Chronicles', 19, 'adults', 4, 'What was the division of jurisdiction between Amariah and Zebadiah in Jerusalem''s central court?', 'Amariah handled all matters pertaining to the LORD (religious/priestly law) while Zebadiah handled matters pertaining to the king (civil/administrative law)', 'Both had equal jurisdiction over all cases regardless of type', 'Amariah handled northern cases and Zebadiah handled southern cases', 'Zebadiah handled criminal cases and Amariah handled civil cases', 'a', '2 Chronicles 19:11 — "Amariah the chief priest is over you in all matters of the LORD; and Zebadiah the son of Ishmael, the ruler of the house of Judah, for all the king''s matters."'),
('2 Chronicles', 19, 'adults', 5, 'What was the role of the Levites specifically in the Jerusalem court system?', 'They were to be officers before the court dealing in all controversies', 'They were to record and archive all legal judgments', 'They served as advocates speaking on behalf of the poor', 'They were responsible for carrying out sentences', 'a', '2 Chronicles 19:11 — "Also the Levites shall be officers before you. Deal courageously."'),
('2 Chronicles', 19, 'adults', 6, 'How does Jehoshaphat''s charge to the judges parallel Moses'' instructions for judges in Deuteronomy?', 'Both call for impartial judgment without respect of persons or bribery, and both ground judicial authority in God''s own character as the ultimate judge of all', 'Jehoshaphat''s system is entirely different from Moses'' design', 'Jehoshaphat added requirements Moses had not included', 'The parallel is coincidental — Jehoshaphat devised the system independently', 'a', '2 Chronicles 19:7 — "There is no iniquity with the LORD our God, nor respect of persons, nor taking of gifts," echoing Deuteronomy 16:19: "Thou shalt not wrest judgment; thou shalt not respect persons, neither take a gift."'),
('2 Chronicles', 19, 'adults', 7, 'What does Jehoshaphat''s post-rebuke behavior — going throughout the people to bring them back to God — suggest about repentance in the Chronicler''s framework?', 'True repentance leads to active reform — Jehoshaphat does not just feel remorse but takes concrete action to rectify the spiritual condition of the nation', 'The tour was a political move to shore up popular support after his embarrassing return from battle', 'Jehoshaphat''s repentance was purely internal and had no external expression', 'The reform tour was mandated by the prophets as a specific penance', 'a', '2 Chronicles 19:4 — "He went out again through the people from Beersheba to mount Ephraim, and brought them back unto the LORD God of their fathers."'),
('2 Chronicles', 19, 'adults', 8, 'What is the significance of "the LORD shall be with the good" as the closing charge to the judges?', 'It grounds judicial integrity in divine presence — right judgment attracts God''s help, making divine partnership the reward for and companion of righteous judgment', 'It is a motivational slogan with no theological depth', 'It implies that corrupt judges will lose military battles', 'It is a promise that righteous judges will be promoted in rank', 'a', '2 Chronicles 19:11 — "Deal courageously, and the LORD shall be with the good," making divine presence contingent on right conduct.');

-- ═══ 2 Chronicles Chapter 20 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 20, 'kids', 1, 'Which nations came against Jehoshaphat in a great army?', 'Moab, Ammon, and the children of Seir', 'Egypt, Assyria, and Babylon', 'Philistia, Syria, and Edom', 'Arabia, Ethiopia, and Libya', 'a', '2 Chronicles 20:1 — "It came to pass after this also, that the children of Moab, and the children of Ammon, and with them other beside the Ammonites, came against Jehoshaphat to battle."'),
('2 Chronicles', 20, 'kids', 2, 'What did Jehoshaphat proclaim throughout all of Judah when he heard the enemies were coming?', 'A fast', 'A day of feasting', 'A war council', 'A census of soldiers', 'a', '2 Chronicles 20:3 — "And Jehoshaphat feared, and set himself to seek the LORD, and proclaimed a fast throughout all Judah."'),
('2 Chronicles', 20, 'kids', 3, 'Who did Jehoshaphat put at the very front of the army to go out before the soldiers?', 'Singers who praised the LORD', 'Priests with the ark of the covenant', 'Elders carrying the law of Moses', 'Young men blowing trumpets', 'a', '2 Chronicles 20:21 — "And when he had consulted with the people, he appointed singers unto the LORD, and that should praise the beauty of holiness, as they went out before the army."'),
-- Teens
('2 Chronicles', 20, 'teens', 1, 'What was the main point of Jehoshaphat''s prayer before the congregation in the temple court?', 'He confessed Judah had no might against the great company, their eyes were upon God, and declared "we know not what to do but our eyes are upon thee"', 'He listed all of Israel''s past victories as proof God would help again', 'He promised to build a new altar if God gave them victory', 'He asked God to show a miraculous sign before the battle', 'a', '2 Chronicles 20:12 — "O our God, wilt thou not judge them? for we have no might against this great company that cometh against us; neither know we what to do: but our eyes are upon thee."'),
('2 Chronicles', 20, 'teens', 2, 'Which Levite gave the prophecy "the battle is not yours, but God''s"?', 'Jahaziel the son of Zechariah', 'Amariah the chief priest', 'Azariah the son of Oded', 'Hanani the seer', 'a', '2 Chronicles 20:14-15 — "Then upon Jahaziel the son of Zechariah...came the Spirit of the LORD...And he said...Thus saith the LORD unto you, Be not afraid nor dismayed by reason of this great multitude; for the battle is not yours, but God''s."'),
('2 Chronicles', 20, 'teens', 3, 'What were the people of Judah to do the next day according to God''s promise through Jahaziel?', 'Go down against them, stand still, and see the salvation of the LORD — they would not need to fight', 'Attack at dawn and God would send confusion into the enemy camp', 'Surround the enemy from three sides while priests prayed', 'March to the valley and God would cause an earthquake', 'a', '2 Chronicles 20:17 — "Ye shall not need to fight in this battle: set yourselves, stand ye still, and see the salvation of the LORD with you...for the LORD will be with you."'),
('2 Chronicles', 20, 'teens', 4, 'What happened among the enemies that destroyed them without Judah fighting?', 'The LORD set ambushments against them and the enemy nations turned on one another and destroyed each other', 'God sent fire from heaven to consume their armies', 'A great earthquake swallowed their camp overnight', 'Disease struck their army and they were too weak to fight', 'a', '2 Chronicles 20:22-23 — "When they began to sing and to praise, the LORD set ambushments against the children of Ammon, Moab, and mount Seir...For the children of Ammon and Moab stood up against the inhabitants of mount Seir...and when they had made an end of the inhabitants of Seir, every one helped to destroy another."'),
('2 Chronicles', 20, 'teens', 5, 'What was the valley called where Judah blessed the LORD after the battle, and why?', 'Berachah, meaning blessing, because they blessed the LORD there', 'Jehoshaphat, meaning the LORD judges', 'Zephathah, where Asa had fought before', 'Achor, meaning trouble turned to hope', 'a', '2 Chronicles 20:26 — "And on the fourth day they assembled themselves in the valley of Berachah; for there they blessed the LORD: therefore the name of the same place was called, The valley of Berachah, unto this day."'),
-- Adults
('2 Chronicles', 20, 'adults', 1, 'What was the historical and theological argument Jehoshaphat made about Israel''s past relationship with the nations now attacking?', 'He argued that God had commanded Israel not to invade these nations when coming from Egypt, yet they now repaid Israel with invasion — so God must judge this injustice', 'He appealed to the Abrahamic covenant as the sole basis for protection', 'He listed Solomon''s treaties with surrounding nations that were being violated', 'He argued that God''s honor among all nations required him to act', 'a', '2 Chronicles 20:10-11 — "And now, behold, the children of Ammon and Moab and mount Seir, whom thou wouldest not let Israel invade...behold, I say, how they reward us, to come to cast us out of thy possession."'),
('2 Chronicles', 20, 'adults', 2, 'What specific description of God''s sovereign power did Jehoshaphat invoke at the opening of his prayer?', 'Art thou not God in heaven? and rulest not thou over all the kingdoms of the heathen? and in thine hand is there not power and might, so that none is able to withstand thee?', 'He praised God as the creator of heaven and earth and sea', 'He called God the covenant keeper who had never failed Israel', 'He described God as the one who destroyed Pharaoh''s army in the sea', 'a', '2 Chronicles 20:6 — "O LORD God of our fathers, art not thou God in heaven? and rulest not thou over all the kingdoms of the heathen? and in thine hand is there not power and might, so that none is able to withstand thee?"'),
('2 Chronicles', 20, 'adults', 3, 'What does Jehoshaphat''s reference to Solomon''s temple dedication in his prayer reveal about his theological reasoning?', 'He invoked the promise God made when Solomon dedicated the temple — that if they cried to God in time of trouble in that house, he would hear and save them', 'He used the temple''s physical glory as a reason God must protect Jerusalem', 'He reminded God that Israel had paid greatly to build the temple', 'He argued that enemies attacking Judah were effectively attacking God''s house', 'a', '2 Chronicles 20:8-9 — "They have built thee a sanctuary therein for thy name, saying, If, when evil cometh upon us...we stand before this house...and cry unto thee in our affliction, then thou wilt hear and help."'),
('2 Chronicles', 20, 'adults', 4, 'What was the immediate corporate response to Jahaziel''s prophecy before the battle even began?', 'Jehoshaphat bowed with his face to the ground and all Judah and Jerusalem fell before the LORD worshipping him, and the Levites praised him with a loud voice', 'They immediately armed themselves and marched out to battle', 'They sent messengers to offer the enemies terms of peace', 'They fasted again through the night in preparation for battle', 'a', '2 Chronicles 20:18-19 — "And Jehoshaphat bowed his head with his face to the ground: and all Judah and the inhabitants of Jerusalem fell before the LORD, worshipping the LORD. And the Levites...stood up to praise the LORD God of Israel with a loud voice on high."'),
('2 Chronicles', 20, 'adults', 5, 'How much spoil did Judah find when they came to the enemy camp, and how long did it take to gather it?', 'More spoil than they could carry — riches, raiment, and precious jewels — and it took three days to gather it', 'They found very little because the enemy had fled taking their possessions', 'One day''s worth of goods was divided equally among the soldiers', 'They found weapons and armour but no treasure or jewels', 'a', '2 Chronicles 20:25 — "And when Jehoshaphat and his people came to take away the spoil of them, they found among them in abundance both riches with the dead bodies, and precious jewels, which they stripped off for themselves, more than they could carry away: and they were three days in gathering of the spoil."'),
('2 Chronicles', 20, 'adults', 6, 'What was the effect of this miraculous victory on the surrounding kingdoms?', 'The fear of God was on all the kingdoms of those countries when they heard the LORD fought against the enemies of Israel', 'All surrounding nations immediately submitted tribute to Jehoshaphat', 'Egypt sent an embassy offering alliance after hearing the news', 'The kingdom of northern Israel was humbled and offered peace', 'a', '2 Chronicles 20:29 — "And the fear of God was on all the kingdoms of those countries, when they had heard that the LORD fought against the enemies of Israel."'),
('2 Chronicles', 20, 'adults', 7, 'What was the failure at the end of the chapter involving Jehoshaphat and Ahaziah''s joint shipping venture?', 'He joined with Ahaziah king of Israel who did wickedly to make ships to go to Tarshish and Eliezer prophesied the ships would be broken — and they were', 'He sent ships to Egypt against God''s command and they sank in a storm', 'He built a navy that sailed into pagan harbors and was condemned', 'He used temple treasury funds to pay for the fleet without permission', 'a', '2 Chronicles 20:35-37 — "And after this did Jehoshaphat king of Judah join himself with Ahaziah king of Israel, who did very wickedly...And Eliezer...prophesied against Jehoshaphat, saying, Because thou hast joined thyself with Ahaziah, the LORD hath broken thy works. And the ships were broken, that they were not able to go to Tarshish."'),
('2 Chronicles', 20, 'adults', 8, 'What does chapter 20 establish as the supreme example of faith in Chronicles, and how does it function literarily in the book?', 'It is the paradigmatic holy war narrative — radical dependence on God, corporate prayer, prophetic word, worship before battle, and miraculous victory — serving as the high point of Jehoshaphat''s reign and a template for trusting God', 'It is primarily a political account showing Judah''s military recovery after Ramoth-gilead', 'The chapter functions mainly as a warning about the dangers of the valley of Berachah', 'The Chronicler uses it to demonstrate that music is the central act of temple worship', 'a', '2 Chronicles 20:17 — "Ye shall not need to fight in this battle: set yourselves, stand ye still, and see the salvation of the LORD," making passive trust in God the central theological statement.');

-- ═══ 2 Chronicles Chapter 21 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 21, 'kids', 1, 'Who became king of Judah after Jehoshaphat?', 'Jehoram his son', 'Jehoshaphat''s brother', 'Ahaziah his nephew', 'Joash his cousin', 'a', '2 Chronicles 21:1 — "Now Jehoshaphat slept with his fathers, and was buried with his fathers in the city of David. And Jehoram his son reigned in his stead."'),
('2 Chronicles', 21, 'kids', 2, 'What terrible thing did Jehoram do to his brothers when he became king?', 'He killed all his brothers with the sword', 'He sent them away to other countries', 'He put them all in prison', 'He took away all their wealth', 'a', '2 Chronicles 21:4 — "Now when Jehoram was risen up to the kingdom of his father, he strengthened himself, and slew all his brethren with the sword."'),
('2 Chronicles', 21, 'kids', 3, 'Which great prophet sent Jehoram a letter warning him of God''s judgment?', 'Elijah', 'Elisha', 'Isaiah', 'Jeremiah', 'a', '2 Chronicles 21:12 — "And there came a writing to him from Elijah the prophet."'),
-- Teens
('2 Chronicles', 21, 'teens', 1, 'What was the main reason Jehoram walked in evil ways according to the text?', 'He had the daughter of Ahab as his wife who influenced him', 'He was corrupted by the priests of Baal in Jerusalem', 'His evil counselors led him astray from the beginning', 'He was bitter about his father giving gifts to other sons', 'a', '2 Chronicles 21:6 — "And he walked in the way of the kings of Israel, like as did the house of Ahab: for he had the daughter of Ahab to wife: and he wrought that which was evil in the eyes of the LORD."'),
('2 Chronicles', 21, 'teens', 2, 'Why did God not destroy Judah despite Jehoram''s great wickedness?', 'Because of the covenant God had made with David to give a light to him and to his sons always', 'Because the people of Judah themselves remained faithful to God', 'Because Jehoshaphat had been so exceptionally righteous', 'Because the temple still stood as a perpetual sign of God''s presence', 'a', '2 Chronicles 21:7 — "Howbeit the LORD would not destroy the house of David, because of the covenant that he had made with David, and as he promised to give a light to him and to his sons for ever."'),
('2 Chronicles', 21, 'teens', 3, 'What nations revolted against Judah during Jehoram''s reign?', 'Edom revolted from under his hand and Libnah revolted also', 'Moab and Ammon rose up against him', 'Philistia and Arabia attacked Jerusalem', 'Syria and Assyria both invaded at once', 'a', '2 Chronicles 21:8,10 — "In his days the Edomites revolted from under the dominion of Judah...Also did Libnah revolt at the same time from under his hand."'),
('2 Chronicles', 21, 'teens', 4, 'What did Elijah''s letter say would happen to Jehoram personally as punishment?', 'He would be smitten with a great plague and his bowels would fall out by reason of the sickness day by day', 'He would be taken captive to Babylon', 'He would be killed in battle by the Philistines', 'A great fire would consume his palace in Jerusalem', 'a', '2 Chronicles 21:14-15 — "Behold, with a great plague will the LORD smite thy people...And thou shalt have great sickness by disease of thy bowels, until thy bowels fall out by reason of the sickness day by day."'),
('2 Chronicles', 21, 'teens', 5, 'How did Jehoram die and what dishonor was shown at his burial?', 'He died of a bowel disease and his people made no burning for him — he departed without being desired and was not buried in the sepulchres of the kings', 'He was killed in battle and buried with great honors', 'He was assassinated by his own servants and buried secretly', 'He died of old age in peace and was buried in the city of David', 'a', '2 Chronicles 21:19-20 — "His bowels fell out by reason of his sickness: so he died of sore diseases...his people made no burning for him...and he departed without being desired."'),
-- Adults
('2 Chronicles', 21, 'adults', 1, 'What high places did Jehoram build and what spiritual effect did they have on the nation?', 'He made high places in the mountains of Judah and caused the inhabitants of Jerusalem to commit fornication and compelled Judah thereto', 'He rebuilt the temples that Asa had destroyed decades earlier', 'He introduced Baal worship into the Jerusalem temple itself', 'He set up golden calves like those at Bethel and Dan in the north', 'a', '2 Chronicles 21:11 — "Moreover he made high places in the mountains of Judah, and caused the inhabitants of Jerusalem to commit fornication, and compelled Judah thereto."'),
('2 Chronicles', 21, 'adults', 2, 'What was the content of Elijah''s letter regarding Jehoram''s religious sins before naming the punishment?', 'He charged Jehoram with not walking in the ways of Jehoshaphat or Asa but walking like the house of Ahab, and killing his brothers who were better than him', 'Elijah primarily charged him with building the high places throughout the land', 'The letter focused on his mistreatment of the Levites and priests', 'Elijah condemned his treaty with the Philistines and Arabians', 'a', '2 Chronicles 21:12-13 — "Thus saith the LORD God of David thy father, Because thou hast not walked in the ways of Jehoshaphat thy father, nor in the ways of Asa king of Judah...and also hast slain thy brethren of thy father''s house."'),
('2 Chronicles', 21, 'adults', 3, 'What Philistine and Arabian attack occurred during Jehoram''s reign and what did they take?', 'They came against Judah and carried away all the substance found in the king''s house and his sons and his wives — only Jehoahaz the youngest son was left', 'They attacked two border cities and carried away livestock only', 'They besieged Jerusalem for six months and were paid off with tribute', 'They raided southern Judah and returned without entering Jerusalem', 'a', '2 Chronicles 21:16-17 — "Moreover the LORD stirred up against Jehoram the spirit of the Philistines, and of the Arabians...And they came up into Judah, and brake into it, and carried away all the substance that was found in the king''s house, and his sons also, and his wives."'),
('2 Chronicles', 21, 'adults', 4, 'What does the phrase "he departed without being desired" communicate about Jehoram''s legacy?', 'It is a uniquely harsh epitaph — his reign was so destructive and despised that even his death provoked no mourning, the opposite of the honored royal burial', 'It means he died in exile away from his people and capital', 'It refers to the fact that no one asked for his body to be returned', 'It is a formula the Chronicler uses for all wicked kings without distinction', 'a', '2 Chronicles 21:20 — "Thirty and two years old was he when he began to reign, and he reigned in Jerusalem eight years, and departed without being desired: notwithstanding they buried him in the city of David, but not in the sepulchres of the kings."'),
('2 Chronicles', 21, 'adults', 5, 'What was the significance of not burying Jehoram in the sepulchres of the kings?', 'It was a public act of condemnation that separated him from the honored line of Davidic kings and reinforced his reputation as a failed king', 'There was simply no room remaining in the royal tombs', 'The priests refused to allow burial in sacred ground because of his disease', 'His body was ceremonially unclean due to the nature of his bowel disease', 'a', '2 Chronicles 21:20 — "They buried him in the city of David, but not in the sepulchres of the kings," contrasting with the honored burials of faithful kings like Asa and Jehoshaphat.'),
('2 Chronicles', 21, 'adults', 6, 'How does the Davidic covenant function in chapter 21 as a restraint on God''s judgment of the entire dynasty?', 'God chooses not to destroy the house of David entirely despite Jehoram''s wickedness because of the eternal covenant — showing that God''s promises outlast human faithlessness, though they do not prevent personal judgment', 'The covenant guarantees prosperity to all Davidic kings regardless of their behavior', 'The covenant only protects the land of Israel, not the king personally', 'God delays judgment here but eventually cancels the Davidic covenant entirely', 'a', '2 Chronicles 21:7 — "Howbeit the LORD would not destroy the house of David, because of the covenant that he had made with David," showing covenant mercy operating alongside retributive justice.'),
('2 Chronicles', 21, 'adults', 7, 'What does Elijah''s letter to Jehoram suggest about the extent of prophetic ministry in Chronicles?', 'It shows prophets operating across kingdom boundaries through written correspondence — Elijah''s letter to a Judahite king demonstrates that prophetic authority transcends political divisions', 'Elijah had no authority over Judah and the letter was a personal opinion only', 'The letter demonstrates that written prophecy was considered less authoritative than spoken prophecy', 'Elijah could only write because he was no longer able to travel to Jerusalem in person', 'a', '2 Chronicles 21:12 — "And there came a writing to him from Elijah the prophet, saying, Thus saith the LORD God of David thy father."'),
('2 Chronicles', 21, 'adults', 8, 'How does Jehoram''s reign serve as a negative foil to his father Jehoshaphat''s in the Chronicler''s narrative design?', 'Every element is inverted: Jehoshaphat sought God, was honored, and died beloved; Jehoram forsook God, killed his brothers, suffered enemy raids, disease, and died unmourned — illustrating the Chronicler''s two-ways theology', 'The Chronicler presents them as equally wicked kings despite their different reputations', 'Jehoram''s story is simply a historical filler between the more important reigns', 'The contrast is only about military success rather than spiritual character', 'a', '2 Chronicles 21:6 compared to 17:3 — Jehoram "walked in the way of the kings of Israel" while Jehoshaphat "walked in the first ways of his father David."');

-- ═══ 2 Chronicles Chapter 22 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 22, 'kids', 1, 'Who became king of Judah after Jehoram, because the Arabians had killed all the other sons?', 'Ahaziah the youngest son', 'Joash the hidden prince', 'Jehoiada the priest', 'Athaliah the queen mother', 'a', '2 Chronicles 22:1 — "And the inhabitants of Jerusalem made Ahaziah his youngest son king in his stead: for the band of men that came with the Arabians to the camp had slain all the eldest."'),
('2 Chronicles', 22, 'kids', 2, 'Who seized the throne of Judah after Ahaziah was killed?', 'Athaliah his mother', 'Jehoiada the priest', 'Jehu the son of Nimshi', 'Joash the son of Ahaziah', 'a', '2 Chronicles 22:10 — "But when Athaliah the mother of Ahaziah saw that her son was dead, she arose and destroyed all the seed royal of the house of Judah."'),
('2 Chronicles', 22, 'kids', 3, 'Who hid the baby prince Joash from Athaliah so she could not kill him?', 'Jehoshabeath the daughter of the king and wife of Jehoiada the priest', 'The high priest Amariah', 'A Levite servant in the temple', 'The royal nurse of the palace', 'a', '2 Chronicles 22:11 — "But Jehoshabeath, the daughter of the king, took Joash the son of Ahaziah, and stole him from among the king''s sons that were slain, and put him and his nurse in a bedchamber."'),
-- Teens
('2 Chronicles', 22, 'teens', 1, 'Who was the chief counselor of Ahaziah''s downfall according to the Chronicler?', 'His mother Athaliah who was his counsellor to do wickedly', 'The priests of Baal who surrounded the court', 'The elders of Israel who had abandoned God', 'Jehu who had previously been his ally', 'a', '2 Chronicles 22:3 — "He also walked in the ways of the house of Ahab: for his mother was his counsellor to do wickedly."'),
('2 Chronicles', 22, 'teens', 2, 'How did Ahaziah die — who killed him and where?', 'Jehu killed him when he went to see wounded Joram king of Israel — he was found hiding in Samaria and brought to Jehu who slew him', 'He was killed in battle against the Syrians at Ramoth-gilead', 'The Philistines killed him on a raid into Judah', 'He died of the same disease as his father Jehoram', 'a', '2 Chronicles 22:9 — "And he sought Ahaziah: and they caught him, (for he was hid in Samaria,) and brought him to Jehu: and when they had slain him, they buried him."'),
('2 Chronicles', 22, 'teens', 3, 'Why did they bury Ahaziah with honor even though he was wicked?', 'Because they said he was the son of Jehoshaphat who sought the LORD with all his heart', 'Because Jehoiada the priest interceded for his burial', 'Because no one was willing to leave a king''s body unburied', 'Because his mother Athaliah demanded a royal funeral', 'a', '2 Chronicles 22:9 — "And he sought Ahaziah...and brought him to Jehu: and when they had slain him, they buried him: Because, said they, he is the son of Jehoshaphat, who sought the LORD with all his heart."'),
('2 Chronicles', 22, 'teens', 4, 'Where did Jehoshabeath hide the infant Joash for six years?', 'In the house of God', 'In the king''s wine cellar', 'In a cave outside Jerusalem', 'In the house of a faithful Levite outside the city', 'a', '2 Chronicles 22:12 — "And he was with them hid in the house of God six years: and Athaliah reigned over the land."'),
('2 Chronicles', 22, 'teens', 5, 'What had happened to Ahaziah''s power base that left no one with strength to hold his kingdom together?', 'His destruction of the house of Ahab meant there was no one of the house of Ahaziah strong enough to retain the kingdom', 'The army had been destroyed by Jehu''s coup in Israel', 'The treasury was empty after his father''s reign', 'The Levites had withdrawn their support from the royal house', 'a', '2 Chronicles 22:9 — "So the house of Ahaziah had no power to keep still the kingdom."'),
-- Adults
('2 Chronicles', 22, 'adults', 1, 'What was the theological explanation the Chronicler gave for Ahaziah''s downfall?', 'His destruction was of God since he had joined with Joram against Jehu whom the LORD had anointed to cut off the house of Ahab', 'He was simply caught in the wrong place at the wrong time during Jehu''s revolt', 'His mother''s counsel was the sole cause of his death', 'God punished him because he had not repaired the temple', 'a', '2 Chronicles 22:7 — "And the destruction of Ahaziah was of God by coming to Joram: for when he was come, he went out with Jehoram against Jehu the son of Nimshi, whom the LORD had anointed to cut off the house of Ahab."'),
('2 Chronicles', 22, 'adults', 2, 'What does the Chronicler mean by saying Ahaziah''s counselors were "the house of Ahab" — what theological point is being made?', 'Ahaziah was so thoroughly under the influence of Ahab''s evil dynasty through his mother that their counsel destroyed him — showing how corruption spreads through family alliances with the ungodly', 'The phrase simply means he hired Israelite advisors for foreign policy', 'The Chronicler is condemning the northern kingdom''s entire administrative tradition', 'It refers specifically to Jezebel''s influence which continued through Athaliah', 'a', '2 Chronicles 22:4 — "Wherefore he did evil in the sight of the LORD like the house of Ahab: for they were his counsellors after the death of his father to his destruction."'),
('2 Chronicles', 22, 'adults', 3, 'What does Athaliah''s action of destroying "all the seed royal of the house of Judah" represent as a threat in the Chronicler''s framework?', 'It nearly extinguished the Davidic line entirely — the one child hidden in the temple represents the thread by which God''s covenant promise to David survived', 'It was simply a political power grab with no theological significance', 'It showed the weakness of the Davidic dynasty at that period', 'Athaliah was fulfilling a judgment God had decreed on Jehoram''s line', 'a', '2 Chronicles 22:10 — "But when Athaliah the mother of Ahaziah saw that her son was dead, she arose and destroyed all the seed royal of the house of Judah," nearly ending the Davidic line.'),
('2 Chronicles', 22, 'adults', 4, 'What is the significance of Jehoshabeath''s identity as both the king''s daughter and wife of the priest Jehoiada?', 'Her dual position gave her both access to the royal children and the sanctuary of the temple — her marriage to the chief priest was the providential arrangement that allowed Joash to be hidden safely', 'She is mentioned only to establish her legal right to act on behalf of the royal family', 'Her priestly household connection is incidental to the narrative', 'The Chronicler includes her name only because she was a woman of unusual bravery', 'a', '2 Chronicles 22:11 — "But Jehoshabeath, the daughter of the king, took Joash...and put him and his nurse in a bedchamber. So Jehoshabeath, the daughter of king Jehoram, the wife of Jehoiada the priest...hid him from Athaliah."'),
('2 Chronicles', 22, 'adults', 5, 'What does the six-year period of Athaliah''s reign represent theologically in the Chronicler''s narrative?', 'It represents the darkest moment for the Davidic covenant — a usurping queen from Ahab''s family on David''s throne with the legitimate heir hidden — yet God preserves his promise even in this crisis', 'It was a relatively stable period of political administration for Judah', 'The six years represent a test of the Levites'' faithfulness to the temple service', 'It is a fulfillment of the curse Elijah pronounced on the house of Ahab', 'a', '2 Chronicles 22:12 — "And he was with them hid in the house of God six years: and Athaliah reigned over the land," with the true king hidden even as the usurper sat on the throne.'),
('2 Chronicles', 22, 'adults', 6, 'How does the account of Ahaziah''s reign demonstrate the Chronicler''s ongoing theme about alliances with the northern kingdom?', 'Ahaziah''s alliance with Joram of Israel and his dependence on Ahab''s household for counsel leads directly to his destruction — reinforcing the pattern established with Jehoshaphat that aligning with the ungodly brings judgment', 'The Chronicler shows that some northern alliances are acceptable if made for good reasons', 'Ahaziah''s problem was military rather than spiritual in the Chronicler''s view', 'The theme of northern alliances is only significant for kings who also build high places', 'a', '2 Chronicles 22:7 — "The destruction of Ahaziah was of God by coming to Joram," linking his fate directly to his alliance with Israel''s wicked king.'),
('2 Chronicles', 22, 'adults', 7, 'How does the Chronicler''s account of chapter 22 differ from the account in 2 Kings regarding Ahaziah''s age?', 'Chronicles says Ahaziah was forty-two years old but Kings says twenty-two — the Chronicles figure is likely a textual error since his father Jehoram died at forty', 'Both accounts agree on Ahaziah''s exact age of twenty-two', 'Chronicles omits his age entirely while Kings gives the figure', 'The discrepancy is explained by different methods of counting regnal years', 'a', '2 Chronicles 22:2 — "Forty and two years old was Ahaziah when he began to reign," compared to 2 Kings 8:26 — "Two and twenty years old was Ahaziah when he began to reign."'),
('2 Chronicles', 22, 'adults', 8, 'What does God''s providential preservation of Joash through Jehoshabeath''s courageous act reveal about divine sovereignty in the Chronicler''s theology?', 'God works through human courage and family loyalty to preserve his covenant purposes even when those purposes appear on the verge of total human destruction — providence operates through ordinary actors', 'The rescue shows that the Davidic line was secure in itself regardless of human danger', 'The Chronicler presents the rescue as primarily a human achievement requiring no divine action', 'God''s preservation of Joash was primarily about the temple rather than the Davidic covenant', 'a', '2 Chronicles 22:11-12 — Jehoshabeath''s act of hiding Joash in the house of God for six years preserving the covenant seed, showing God''s purposes working through human faithfulness.');

-- ═══ 2 Chronicles Chapter 23 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 23, 'kids', 1, 'Who organized the plan to make young Joash the rightful king?', 'Jehoiada the priest', 'The chief of the army', 'The elders of Judah', 'The prophet Isaiah', 'a', '2 Chronicles 23:1 — "And in the seventh year Jehoiada strengthened himself, and took the captains of hundreds, Azariah the son of Jeroham...and they went about in Judah."'),
('2 Chronicles', 23, 'kids', 2, 'What happened to Athaliah when she heard the trumpets and shouts of the people crowning Joash king?', 'She cried "Treason, Treason!" and was taken out of the temple and killed', 'She fled to Egypt to escape', 'She surrendered peacefully to Jehoiada', 'She hid in the palace inner rooms', 'a', '2 Chronicles 23:13,15 — "And when Athaliah heard the noise of the people running and praising the king, she came to the people...And she rent her clothes, and said, Treason, Treason...And they laid hands on her; and when she was come to the entering of the horse gate by the king''s house, they slew her there."'),
('2 Chronicles', 23, 'kids', 3, 'What did the people do to the temple of Baal and its priest after Joash was crowned?', 'They broke it down and killed the priest Mattan before the altars', 'They burned it with fire', 'They turned it into a storehouse for the temple', 'They sealed it shut permanently', 'a', '2 Chronicles 23:17 — "Then all the people went to the house of Baal, and brake it down, and brake his altars and his images in pieces, and slew Mattan the priest of Baal before the altars."'),
-- Teens
('2 Chronicles', 23, 'teens', 1, 'What covenant did Jehoiada make when he crowned Joash, and between whom?', 'A covenant between himself, the people, and the king that they would be the LORD''s people', 'A treaty between Judah and the northern tribes to reunite the kingdom', 'A covenant between the new king and the army commanders', 'A promise between the Levites and the priests to guard the temple', 'a', '2 Chronicles 23:3 — "And all the congregation made a covenant with the king in the house of God. And he said unto them, Behold, the king''s son shall reign, as the LORD hath said of the sons of David."'),
('2 Chronicles', 23, 'teens', 2, 'What was the role of the Levites and the captains of hundreds in the temple during the coronation ceremony?', 'The Levites surrounded the king with weapons, anyone entering the temple would be killed, and the priests handled the regular temple service', 'They all stood outside the temple gates to guard the exits', 'They formed two lines leading from the palace to the temple', 'They stood on the walls of Jerusalem to signal the city', 'a', '2 Chronicles 23:7 — "And the Levites shall compass the king round about, every man with his weapons in his hand; and whosoever else cometh into the house, he shall be put to death: but be ye with the king when he cometh in, and when he goeth out."'),
('2 Chronicles', 23, 'teens', 3, 'What specific items were given to Joash when he was crowned?', 'The crown and the testimony (the law) were put upon him', 'A golden sceptre and the royal robes of David', 'The sword of the LORD and the anointing oil', 'A signet ring and the key of the house of David', 'a', '2 Chronicles 23:11 — "Then they brought out the king''s son, and put upon him the crown, and gave him the testimony, and made him king."'),
('2 Chronicles', 23, 'teens', 4, 'What covenant did Jehoiada make after Athaliah was killed and the temple of Baal destroyed?', 'A covenant between himself, all the people, and the king that they would be the LORD''s people', 'A treaty with the surrounding nations to recognize Joash as king', 'A covenant to never again allow a foreign queen on the throne', 'An agreement to hold an annual feast commemorating the restoration', 'a', '2 Chronicles 23:16 — "And Jehoiada made a covenant between him, and between all the people, and between the king, that they should be the LORD''s people."'),
('2 Chronicles', 23, 'teens', 5, 'What offices did Jehoiada restore and reorganize in the temple after the coup?', 'He appointed the offices of the house of the LORD under the Levitical priests whom David had divided, with singers and porters — as David had commanded', 'He replaced all the former priests with new ones loyal to him', 'He gave the Levites new duties not prescribed in the law of Moses', 'He restored only the morning and evening offerings which had lapsed', 'a', '2 Chronicles 23:18 — "Also Jehoiada appointed the offices of the house of the LORD by the hand of the priests the Levites, whom David had distributed in the house of the LORD, to offer the burnt offerings of the LORD, as it is written in the law of Moses."'),
-- Adults
('2 Chronicles', 23, 'adults', 1, 'What was the precise military and political plan Jehoiada used to execute the coup, involving the Sabbath rotation of gatekeepers?', 'He arranged that those coming on and going off the Sabbath duty should both remain — tripling the guard — with one third at the king''s house, a third at the gate of the foundation, and a third at the gate behind the guard', 'He waited until all the guards were changed simultaneously and struck in that moment', 'He bribed the commanders of the army to support Joash', 'He used the Passover celebration as cover for the gathering of armed men', 'a', '2 Chronicles 23:4-5 — "This is the thing that ye shall do; A third part of you entering on the sabbath, of the priests and of the Levites, shall be porters of the doors; And a third part shall be at the king''s house; and a third part at the gate of the foundation."'),
('2 Chronicles', 23, 'adults', 2, 'What was the theological basis Jehoiada gave for the coup — how did he justify the action?', 'Behold, the king''s son shall reign as the LORD hath said of the sons of David — the coup was not rebellion but restoration of the divinely mandated Davidic succession', 'He argued that Athaliah was a foreigner and therefore had no right to reign', 'He presented it as fulfilling Elijah''s prophecy against the house of Ahab', 'He invoked the law of Moses which forbade women from ruling', 'a', '2 Chronicles 23:3 — "And all the congregation made a covenant with the king in the house of God. And he said unto them, Behold, the king''s son shall reign, as the LORD hath said of the sons of David."'),
('2 Chronicles', 23, 'adults', 3, 'What does the giving of the testimony (the law) alongside the crown reveal about the Chronicler''s concept of Davidic kingship?', 'It shows that legitimate Davidic kingship is covenantally defined — the king receives divine law alongside royal authority, making his rule subject to and shaped by God''s word from the moment of coronation', 'The testimony was simply a ceremonial object with no practical significance', 'The law was given to remind the young king to study it later when he was older', 'It was a standard coronation ceremony that all kings underwent automatically', 'a', '2 Chronicles 23:11 — "Then they brought out the king''s son, and put upon him the crown, and gave him the testimony, and made him king," placing law and crown together as inseparable.'),
('2 Chronicles', 23, 'adults', 4, 'What was the crowd''s response when Joash was crowned and anointed — what was the atmosphere?', 'They said "God save the king" and the people rejoiced and the city was quiet after Athaliah was slain with the sword', 'They wept with joy but remained reverent and silent in the temple', 'They shouted battle cries and marched to destroy the Baal temple immediately', 'They praised God with instruments for three days continuously', 'a', '2 Chronicles 23:11,13,21 — "And they said, God save the king...and all the people of the land rejoiced...So all the people of the land rejoiced, and the city was quiet, after that they had slain Athaliah with the sword."'),
('2 Chronicles', 23, 'adults', 5, 'What does Jehoiada''s careful instruction that only the priests and ministering Levites could enter the temple during the coronation reveal about his theology of sacred space?', 'He maintained the distinction of sacred and common space even in a political crisis — the coup did not override the holiness code, showing that right worship and right action must coexist', 'He was simply trying to limit the number of armed men in one place for security reasons', 'The restriction on entry was purely a military security measure with no religious meaning', 'He was protecting the secrecy of the plan from those who might warn Athaliah', 'a', '2 Chronicles 23:6 — "But let none come into the house of the LORD, save the priests, and they that minister of the Levites; they shall go in, for they are holy: but all the people shall keep the watch of the LORD."'),
('2 Chronicles', 23, 'adults', 6, 'What does the destruction of the Baal temple and killing of its priest Mattan represent in the Chronicler''s reform narrative?', 'It shows the coup was not merely political but covenantal — the restoration of Davidic rule necessarily entailed the elimination of Baal worship that Athaliah had promoted under the influence of Ahab''s house', 'The destruction was an act of popular mob vengeance with no theological direction', 'Jehoiada destroyed the Baal temple primarily to remove a political rival institution', 'The Baal temple was destroyed only because it had been built on royal property', 'a', '2 Chronicles 23:17 — "Then all the people went to the house of Baal, and brake it down, and brake his altars and his images in pieces, and slew Mattan the priest of Baal before the altars."'),
('2 Chronicles', 23, 'adults', 7, 'How does Jehoiada''s restoration of the Davidic order of temple worship (citing David''s arrangement) reinforce the Chronicler''s broader theological program?', 'The Chronicler consistently presents David''s arrangement of temple worship as the normative standard — its restoration after Athaliah''s usurpation confirms the coup as a return to legitimate divine order', 'The citation of David is simply an antiquarian note without theological weight', 'The Chronicler is primarily interested in Jehoiada''s administrative skill', 'The reference to David is used to legitimize Jehoiada''s personal authority', 'a', '2 Chronicles 23:18 — "Jehoiada appointed the offices of the house of the LORD...as David had distributed in the house of the LORD...as it is written in the law of Moses, with rejoicing and with singing, as it was ordained by David."'),
('2 Chronicles', 23, 'adults', 8, 'What does the statement "all the people of the land rejoiced and the city was quiet" after the coup suggest about the nature of Athaliah''s reign?', 'It implies her rule was experienced as oppressive and illegitimate by the people — the restoration of the Davidic heir brought genuine relief and joy, not just political change', 'The city''s quietness was merely the absence of military conflict after the fighting ended', 'The people''s joy was primarily relief at having any king rather than a specific attachment to the Davidic line', 'The quiet meant the people were indifferent to who ruled as long as order was maintained', 'a', '2 Chronicles 23:21 — "So all the people of the land rejoiced, and the city was quiet, after that they had slain Athaliah with the sword," contrasting the usurper''s removal with the restoration of rightful covenant kingship.');

-- ═══ 2 Chronicles Chapter 24 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 24, 'kids', 1, 'How old was Joash when he became king and how long did he reign in Jerusalem?', 'He was seven years old when he began to reign and he reigned forty years in Jerusalem', 'He was twelve years old and reigned thirty years', 'He was five years old and reigned twenty-five years', 'He was ten years old and reigned forty-five years', 'a', '2 Chronicles 24:1 — "Joash was seven years old when he began to reign, and he reigned forty years in Jerusalem."'),
('2 Chronicles', 24, 'kids', 2, 'What did Joash put outside the temple gate to collect money for repairs?', 'A chest', 'A table of gold', 'A basket of cedar', 'A bowl of bronze', 'a', '2 Chronicles 24:8 — "And at the king''s commandment they made a chest, and set it without at the gate of the house of the LORD."'),
('2 Chronicles', 24, 'kids', 3, 'Who was stoned to death for telling the people they had forsaken the LORD?', 'Zechariah the son of Jehoiada the priest', 'Isaiah the prophet', 'Elisha the man of God', 'Hanani the seer', 'a', '2 Chronicles 24:20-21 — "And the Spirit of God came upon Zechariah the son of Jehoiada the priest...And they conspired against him, and stoned him with stones at the commandment of the king."'),
-- Teens
('2 Chronicles', 24, 'teens', 1, 'What was the state of the temple that Joash wanted to repair?', 'It had been broken up and the dedicated things of the house of the LORD had Athaliah''s sons used for Baalim', 'The walls had been damaged in Jehu''s invasion of Jerusalem', 'The roof had collapsed during an earthquake in Jehoshaphat''s time', 'The bronze pillars had been stolen by the Egyptians under Shishak', 'a', '2 Chronicles 24:7 — "For the sons of Athaliah, that wicked woman, had broken up the house of God; and also all the dedicated things of the house of the LORD did they bestow upon Baalim."'),
('2 Chronicles', 24, 'teens', 2, 'What did the chest for temple repairs contain when it was brought to the king by the Levites?', 'Much money — and the king and Jehoiada''s scribe counted it and hired masons and carpenters to repair the house of the LORD', 'Empty offerings of grain instead of the required silver', 'Gold and silver from the northern tribes who had contributed', 'Only the offerings of the priests but none from the people', 'a', '2 Chronicles 24:11 — "Now it came to pass, that at what time the chest was brought unto the king''s office by the hand of the Levites...when they saw that there was much money, the king''s scribe and the high priest''s officer came and emptied the chest."'),
('2 Chronicles', 24, 'teens', 3, 'What happened to Joash after Jehoiada the priest died at the age of 130?', 'The princes of Judah came and made obeisance to him and he hearkened to them and forsook the house of the LORD to serve groves and idols', 'He became even more devoted to the temple service on his own', 'He appointed his own son as priest in Jehoiada''s place', 'He continued all the reforms without Jehoiada''s guidance', 'a', '2 Chronicles 24:17-18 — "Now after the death of Jehoiada came the princes of Judah, and made obeisance to the king...And they left the house of the LORD God of their fathers, and served groves and idols."'),
('2 Chronicles', 24, 'teens', 4, 'What were the dying words of Zechariah son of Jehoiada as he was being stoned?', 'The LORD look upon it, and require it', 'God will avenge my blood upon you all', 'Forgive them Father for they know not what they do', 'May the LORD not forget this evil deed', 'a', '2 Chronicles 24:22 — "And when he died, he said, The LORD look upon it, and require it."'),
('2 Chronicles', 24, 'teens', 5, 'How was Joash punished for his wickedness against Zechariah and the prophets?', 'A small army of Syrians came and destroyed the princes and the people; Joash was left sick and his servants conspired against him and slew him in his bed', 'He was defeated by a great army from Egypt', 'God sent a plague that killed his children', 'Edom invaded and captured Jerusalem''s treasures', 'a', '2 Chronicles 24:23-25 — "And it came to pass at the end of the year, that the host of Syria came up against him...And they left him in great diseases. And his own servants conspired against him...and slew him on his bed, and he died."'),
-- Adults
('2 Chronicles', 24, 'adults', 1, 'What was the administrative procedure Joash established for the temple repair collection, and why had the Levites been slow to act?', 'He commanded a chest be set outside the gate and a proclamation made in Judah and Jerusalem; the Levites had not been hasty in the work of gathering the money', 'He instituted a special Sabbath tax on all landowners in Judah', 'He required the temple priests to personally solicit donations from every household', 'He used only the existing temple treasury without collecting new funds', 'a', '2 Chronicles 24:8-10 — "And at the king''s commandment they made a chest, and set it without at the gate of the house of the LORD...And all the princes and all the people rejoiced, and brought in, and cast into the chest, until they had made an end."'),
('2 Chronicles', 24, 'adults', 2, 'What does the text say was done with the money collected — what was the priority established for its use?', 'They used it to hire masons and carpenters to repair the house of the LORD, and also wrought iron and brass to mend the house; after the repairs were done the residue was used for temple vessels', 'All the money went directly to the priests for their maintenance', 'Half was used for building and half for temple furnishings immediately', 'The money was given to the king first and he distributed it to the craftsmen', 'a', '2 Chronicles 24:12-14 — "And they set it right...and hired masons and carpenters to repair the house of the LORD...And when they had finished it, they brought the rest of the money before the king and Jehoiada, whereof were made vessels of gold and silver."'),
('2 Chronicles', 24, 'adults', 3, 'What was the honor given to Jehoiada at his death that was unprecedented for a non-king?', 'He was buried among the kings in the city of David because he had done good in Israel both toward God and toward his house', 'He was given a state funeral with the full mourning period of thirty days', 'A monument was erected to him at the temple gate in his memory', 'His name was inscribed in the book of the kings of Judah', 'a', '2 Chronicles 24:16 — "And they buried him in the city of David among the kings, because he had done good in Israel, both toward God, and toward his house."'),
('2 Chronicles', 24, 'adults', 4, 'What does the speed of Joash''s apostasy after Jehoiada''s death reveal about the nature of his earlier faithfulness?', 'His faithfulness was largely dependent on Jehoiada''s mentorship rather than deeply rooted personal conviction — when the godly influence was removed, the princes of Judah''s flattery led him immediately into idolatry', 'His apostasy shows that all kings eventually fail no matter how well they begin', 'The princes had been secretly corrupting Joash for years before Jehoiada died', 'His fall was caused by political pressure from the northern kingdom rather than internal failure', 'a', '2 Chronicles 24:2,18 — "Joash did that which was right...all the days of Jehoiada the priest...And they left the house of the LORD God of their fathers, and served groves and idols," showing the conditional nature of his goodness.'),
('2 Chronicles', 24, 'adults', 5, 'What made Joash''s killing of Zechariah particularly heinous according to the narrative context?', 'Zechariah was the son of Jehoiada who had saved Joash''s life and been his guardian — Joash forgot the kindness of Jehoiada his father and killed his son, showing ingratitude compounding the crime', 'Zechariah was killed in the temple court itself which was sacred ground', 'Zechariah was an elderly man too weak to flee or defend himself', 'Zechariah had been a personal friend to Joash from childhood', 'a', '2 Chronicles 24:22 — "Thus Joash the king remembered not the kindness which Jehoiada his father had done to him, but slew his son."'),
('2 Chronicles', 24, 'adults', 6, 'How does the Chronicler use the Syrian invasion to illustrate divine retribution in chapter 24?', 'A small Syrian army defeated a much larger Judahite force because Judah had forsaken the LORD — the military defeat is explicitly linked to their abandonment of God as immediate divine judgment', 'The Syrian victory was due to superior military tactics rather than divine judgment', 'The defeat is presented as politically significant but without theological comment', 'God used the invasion to punish the princes rather than Joash personally', 'a', '2 Chronicles 24:24 — "For the army of the Syrians came with a small company of men, and the LORD delivered a very great host into their hand, because they had forsaken the LORD God of their fathers."'),
('2 Chronicles', 24, 'adults', 7, 'What does Jesus'' reference to "Zacharias son of Barachias" in Matthew 23:35 suggest about how the stoning of Zechariah was remembered in Jewish tradition?', 'Jesus cited Zechariah as the last righteous martyr killed in the Hebrew scriptures (from Abel at the beginning to Zechariah at the end of the Hebrew canon), making him a symbol of all prophetic blood shed by Israel', 'Jesus was referring to a different Zechariah from a later period', 'The reference in Matthew is an error because the father''s name differs between Matthew and Chronicles', 'Zechariah''s death had been forgotten and Jesus was restoring the memory of it', 'a', '2 Chronicles 24:20-22 — Zechariah son of Jehoiada was stoned in the temple court, referenced by Jesus in Matthew 23:35 as the bookend of righteous martyrdom in the Hebrew scriptures.'),
('2 Chronicles', 24, 'adults', 8, 'How does the arc of Joash''s reign in chapter 24 — from hiding in the temple as an infant, to repairing it, to killing God''s prophet in its court — function as a theological statement about the human heart?', 'It shows that even those who begin well and accomplish great things for God can fall catastrophically when they choose human approval (the princes'' flattery) over divine faithfulness — external piety cannot substitute for inward devotion', 'The arc is simply a historical account without intentional theological shaping', 'It shows that all Davidic kings were fundamentally corrupt from the beginning', 'The Chronicler uses Joash to argue that only priests, not kings, can be trusted with spiritual leadership', 'a', '2 Chronicles 24:2 — "Joash did that which was right...all the days of Jehoiada," and verse 18 — "they left the house of the LORD," showing how quickly covenantal faithfulness can unravel without sustained personal commitment.');
